  useEffect(() => {
    const loadConstants = async () => {
      const { DEFAULT_TRANSIENT_RECOVERY_SETTINGS, TRANSIENT_RECOVERY_KEYS } = await import("@/features/observability/constants");
      setConstants({ DEFAULT_TRANSIENT_RECOVERY_SETTINGS, TRANSIENT_RECOVERY_KEYS });
    };
    loadConstants();
  }, []);

  if (settingsQuery.isLoading || !settingsQuery.data || !constants) {
    return <div className="p-10 text-center text-gray-400">Loading settings...</div>;
  }

  const stored = parseJsonSetting<TransientRecoverySettings | null>(
    settingsQuery.data.get(constants.TRANSIENT_RECOVERY_KEYS.settings),
    null
  );

  const initialSettings: TransientRecoverySettings = stored
    ? {
        enabled: stored.enabled ?? constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.enabled,
        retry: {
          enabled:
            stored.retry?.enabled ?? constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.retry.enabled,
          maxAttempts:
            stored.retry?.maxAttempts ??
            constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.retry.maxAttempts,
          initialDelayMs:
            stored.retry?.initialDelayMs ??
            constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.retry.initialDelayMs,
          maxDelayMs:
            stored.retry?.maxDelayMs ??
            constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.retry.maxDelayMs,
          timeoutMs:
            stored.retry?.timeoutMs === null
              ? 0
              : stored.retry?.timeoutMs ??
                constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.retry.timeoutMs,
        },
        circuit: {
          enabled:
            stored.circuit?.enabled ??
            constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.circuit.enabled,
          failureThreshold:
            stored.circuit?.failureThreshold ??
            constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.circuit.failureThreshold,
          resetTimeoutMs:
            stored.circuit?.resetTimeoutMs ??
            constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS.circuit.resetTimeoutMs,
        },
      }
    : constants.DEFAULT_TRANSIENT_RECOVERY_SETTINGS;

  return <TransientRecoverySettingsForm initialSettings={initialSettings} recoveryKeys={constants.TRANSIENT_RECOVERY_KEYS} />;
}

function TransientRecoverySettingsForm({
  initialSettings,
  recoveryKeys,
}: {
  initialSettings: TransientRecoverySettings;
  recoveryKeys: { settings: string };
}) {
  const { toast } = useToast();
  const [settings, setSettings] = useState<TransientRecoverySettings>(initialSettings);
  const [dirty, setDirty] = useState(false);
  const settingsQuery = useSettingsMap();
  const updateSetting = useUpdateSetting();

  const updateRetry = (key: keyof TransientRecoverySettings["retry"], value: number | boolean): void => {
    setSettings((prev: TransientRecoverySettings) => ({
      ...prev,
      retry: {
        ...prev.retry,
        [key]: value,
      },
    }));
    setDirty(true);
  };

  const updateCircuit = (
    key: keyof TransientRecoverySettings["circuit"],
    value: number | boolean
  ): void => {
    setSettings((prev: TransientRecoverySettings) => ({
      ...prev,
      circuit: {
        ...prev.circuit,
        [key]: value,
      },
    }));
    setDirty(true);
  };

  const saveSettings = async (): Promise<void> => {
    try {
      const payload: TransientRecoverySettings = {
        enabled: settings.enabled,
        retry: {
          ...settings.retry,
          timeoutMs:
            settings.retry.timeoutMs && settings.retry.timeoutMs > 0
              ? settings.retry.timeoutMs
              : null,
        },
        circuit: {
          ...settings.circuit,
        },
      };
      await updateSetting.mutateAsync({
        key: recoveryKeys.settings,
        value: serializeSetting(payload),
      });
      setDirty(false);
      toast("Transient recovery settings saved.", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to save settings.", {
        variant: "error",
      });
    }
  };

  return (
    <div className="container mx-auto py-10 space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-white">Transient Recovery</h1>
        <p className="mt-2 text-sm text-gray-400">
          Configure retry and circuit-breaker policies for transient failures.
        </p>
      </div>

      <div className="rounded-md border border-gray-800 bg-gray-950 p-4 space-y-6">
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div>
            <h2 className="text-lg font-semibold text-white">Global toggle</h2>
            <p className="mt-1 text-xs text-gray-400">
              Disable to skip all retries and circuit breakers across the app.
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Label className="text-xs text-gray-400">Enabled</Label>
            <Switch
              checked={settings.enabled}
              onCheckedChange={(checked: boolean) => {
                setSettings((prev: TransientRecoverySettings) => ({ ...prev, enabled: checked }));
                setDirty(true);
              }}
            />
          </div>
        </div>

        <div className="grid gap-6 md:grid-cols-2">
          <div className="space-y-4 rounded-md border border-gray-800 bg-gray-900 p-4">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-sm font-semibold text-white">Retry policy</h3>
                <p className="text-xs text-gray-400">
                  Applies to transient external calls and webhooks.
                </p>
              </div>
              <div className="flex items-center gap-2">
                <Label className="text-xs text-gray-400">Enabled</Label>
                <Switch
                  checked={settings.retry.enabled}
                  onCheckedChange={(checked: boolean) => updateRetry("enabled", checked)}
                />
              </div>
            </div>

            <div className="grid gap-3">
              <div className="grid gap-1">
                <Label className="text-xs text-gray-400">Max attempts</Label>
                <Input
                  type="number"
                  min={1}
                  value={settings.retry.maxAttempts}
                  onChange={(event: ChangeEvent<HTMLInputElement>) =>
                    updateRetry(
                      "maxAttempts",
                      toNumber(event.target.value, settings.retry.maxAttempts, 1)
                    )
                  }
                  disabled={settingsQuery.isPending}
                />
              </div>
              <div className="grid gap-1">
                <Label className="text-xs text-gray-400">Initial delay (ms)</Label>
                <Input
                  type="number"
                  min={0}
                  value={settings.retry.initialDelayMs}
                  onChange={(event: ChangeEvent<HTMLInputElement>) =>
                    updateRetry(
                      "initialDelayMs",
                      toNumber(event.target.value, settings.retry.initialDelayMs)
                    )
                  }
                  disabled={settingsQuery.isPending}
                />
              </div>
              <div className="grid gap-1">
                <Label className="text-xs text-gray-400">Max delay (ms)</Label>
                <Input
                  type="number"
                  min={0}
                  value={settings.retry.maxDelayMs}
                  onChange={(event: ChangeEvent<HTMLInputElement>) =>
                    updateRetry(
                      "maxDelayMs",
                      toNumber(event.target.value, settings.retry.maxDelayMs)
                    )
                  }
                  disabled={settingsQuery.isPending}
                />
              </div>
              <div className="grid gap-1">
                <Label className="text-xs text-gray-400">Timeout per attempt (ms)</Label>
                <Input
                  type="number"
                  min={0}
                  value={settings.retry.timeoutMs ?? 0}
                  onChange={(event: ChangeEvent<HTMLInputElement>) =>
                    updateRetry(
                      "timeoutMs",
                      toNumber(event.target.value, settings.retry.timeoutMs ?? 0)
                    )
                  }
                  disabled={settingsQuery.isPending}
                />
                <p className="text-[11px] text-gray-500">
                  Set to 0 to disable per-attempt timeout.
                </p>
              </div>
            </div>
          </div>

          <div className="space-y-4 rounded-md border border-gray-800 bg-gray-900 p-4">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-sm font-semibold text-white">Circuit breaker</h3>
                <p className="text-xs text-gray-400">
                  Prevents repeated calls to failing services.
                </p>
              </div>
              <div className="flex items-center gap-2">
                <Label className="text-xs text-gray-400">Enabled</Label>
                <Switch
                  checked={settings.circuit.enabled}
                  onCheckedChange={(checked: boolean) => updateCircuit("enabled", checked)}
                />
              </div>
            </div>

            <div className="grid gap-3">
              <div className="grid gap-1">
                <Label className="text-xs text-gray-400">Failure threshold</Label>
                <Input
                  type="number"
                  min={1}
                  value={settings.circuit.failureThreshold}
                  onChange={(event: ChangeEvent<HTMLInputElement>) =>
                    updateCircuit(
                      "failureThreshold",
                      toNumber(
                        event.target.value,
                        settings.circuit.failureThreshold,
                        1
                      )
                    )
                  }
                  disabled={settingsQuery.isPending}
                />
              </div>
              <div className="grid gap-1">
                <Label className="text-xs text-gray-400">Reset timeout (ms)</Label>
                <Input
                  type="number"
                  min={0}
                  value={settings.circuit.resetTimeoutMs}
                  onChange={(event: ChangeEvent<HTMLInputElement>) =>
                    updateCircuit(
                      "resetTimeoutMs",
                      toNumber(
                        event.target.value,
                        settings.circuit.resetTimeoutMs
                      )
                    )
                  }
                  disabled={settingsQuery.isPending}
                />
              </div>
            </div>
          </div>
        </div>

        <div className="flex items-center justify-between">
          <p className="text-xs text-gray-500">
            Changes apply across the app after saving.
          </p>
          <Button
            size="sm"
            onClick={() => void saveSettings()}
            disabled={!dirty || updateSetting.isPending}
          >
            {updateSetting.isPending ? "Saving..." : "Save settings"}
          </Button>
        </div>
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { ObjectId, Sort } from "mongodb";

import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { parseJsonBody } from "@/features/products/server";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { internalError } from "@/shared/errors/app-error";
import { enforceAiPathsActionRateLimit, requireAiPathsAccess } from "@/features/ai-paths/server";

const querySchema = z.object({
  provider: z.enum(["auto", "mongodb"]).optional(),
  collection: z.string().trim().min(1),
  query: z.record(z.string(), z["unknown"]()).optional(),
  projection: z.record(z.string(), z["unknown"]()).optional(),
  sort: z.record(z.string(), z.union([z.number(), z.literal("asc"), z.literal("desc")])).optional(),
  limit: z.number().int().min(1).max(200).optional(),
  single: z.boolean().optional(),
  idType: z.enum(["string", "objectId"]).optional(),
});

const ALLOWED_COLLECTIONS = new Set([
  "products",
  "product_drafts",
  "product_categories",
  "product_tags",
  "catalogs",
  "image_files",
  "product_listings",
  "product_ai_jobs",
  "integrations",
  "integration_connections",
  "settings",
  "users",
  "user_preferences",
  "languages",
  "system_logs",
  "notes",
  "tags",
  "categories",
  "notebooks",
  "noteFiles",
  "themes",
  "chatbot_sessions",
  "auth_security_attempts",
  "auth_security_profiles",
  "auth_login_challenges",
]);

const coerceQuery = (value: unknown): Record<string, unknown> => {
  if (!value) return {};
  if (typeof value === "string") {
    try {
      return JSON.parse(value) as Record<string, unknown>;
    } catch {
      return {};
    }
  }
  if (typeof value === "object") {
    return value as Record<string, unknown>;
  }
  return {};
};

const looksLikeObjectId = (value: string): boolean => /^[0-9a-fA-F]{24}$/.test(value);

const normalizeObjectId = (query: Record<string, unknown>, idType?: string): Record<string, unknown> => {
  if (idType !== "objectId") return query;
  const next = { ...query };
  if (typeof next._id === "string" && looksLikeObjectId(next._id)) {
    next._id = new ObjectId(next._id);
  }
  return next;
};

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const access = await requireAiPathsAccess();
    enforceAiPathsActionRateLimit(access, "db-query");
    const parsed = await parseJsonBody(req, querySchema, {
      logPrefix: "ai-paths.db-query",
    });
    if (!parsed.ok) return parsed.response;
    if (!process.env.MONGODB_URI) {
      return createErrorResponse(internalError("MongoDB is not configured"), {
        request: req,
        source: "ai-paths.db-query",
      });
    }
    const data = parsed.data as z.infer<typeof querySchema>;
    const {
      collection,
      query,
      projection,
      sort,
      limit = 20,
      single = false,
      idType,
    } = data;

    if (!ALLOWED_COLLECTIONS.has(collection)) {
      return createErrorResponse(internalError("Collection not allowlisted"), {
        request: req,
        source: "ai-paths.db-query",
      });
    }

    const mongo = await getMongoDb();
    const filter = normalizeObjectId(coerceQuery(query), idType);

    if (single) {
      const item = await mongo
        .collection(collection)
        .findOne(filter, projection ? { projection } : undefined);
      return NextResponse.json({ item, count: item ? 1 : 0 });
    }

    const cursor = mongo.collection(collection).find(filter, projection ? { projection } : undefined);
    if (sort) {
      cursor.sort(sort as Sort);
    }
    const items = await cursor.limit(limit).toArray();
    return NextResponse.json({ items, count: items.length });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.db-query",
      fallbackMessage: "Failed to execute database query",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 { source: "ai-paths.db-query" });

