  updates: z.record(z.string(), z["unknown"]()).optional(),
  mode: z.enum(["replace", "append"]).optional(),
});

const mergeAppendValue = (current: unknown, next: unknown): unknown => {
  if (next === undefined) return undefined;
  if (current === undefined || current === null) return next;
  if (Array.isArray(current)) {
    const currentArr = current as unknown[];
    if (Array.isArray(next)) {
      return [...currentArr, ...(next as unknown[])];
    }
    return [...currentArr, next];
  }
  if (typeof current === "string" && typeof next === "string") {
    if (!current) return next;
    if (!next) return current;
    return `${current}\n${next}`;
  }
  if (
    current &&
    typeof current === "object" &&
    next &&
    typeof next === "object" &&
    !Array.isArray(next)
  ) {
    return { ...(current as Record<string, unknown>), ...(next as Record<string, unknown>) };
  }
  return next;
};

const applyAppendMode = (
  updates: Record<string, unknown>,
  current: Record<string, unknown>
): Record<string, unknown> => {
  const next: Record<string, unknown> = {};
  Object.entries(updates).forEach(([key, value]: [string, unknown]) => {
    next[key] = mergeAppendValue(current[key], value);
  });
  return next;
};

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const access = await requireAiPathsAccess();
    enforceAiPathsActionRateLimit(access, "entity-update");
    const parsed = await parseJsonBody(req, updateSchema, {
      logPrefix: "ai-paths.update",
    });
    if (!parsed.ok) return parsed.response;

    const data = parsed.data as z.infer<typeof updateSchema>;
    const { entityType, entityId, updates, mode } = data;
    const normalizedUpdates =
      updates && typeof updates === "object" ? updates : {};

    if (Object.keys(normalizedUpdates).length === 0) {
      throw badRequestError("No updates provided");
    }

    if (entityType !== "custom" && !entityId?.trim()) {
      throw badRequestError("Entity id is required");
    }

    if (entityType === "custom") {
      return NextResponse.json({
        ok: true,
        entityType,
        entityId: entityId ?? null,
        updates: normalizedUpdates,
        note: "Custom entities are not persisted yet.",
      });
    }

    if (entityType === "product") {
      ensureAiPathsPermission(access, "products.manage", "Forbidden.");
      const productRepository = await getProductRepository();
      const existing =
        mode === "append" ? await productRepository.getProductById(entityId as string) : null;
      if (mode === "append" && !existing) {
        throw notFoundError("Product not found", { productId: entityId });
      }
      const prepared =
        mode === "append" && existing
          ? applyAppendMode(normalizedUpdates, existing as Record<string, unknown>)
          : normalizedUpdates;
      const validated = productUpdateSchema.safeParse(prepared);
      if (!validated.success) {
        throw validationError("Invalid product update", {
          issues: validated.error.flatten(),
        });
      }
      const updateData = removeUndefined(validated.data);
      if (Object.keys(updateData).length === 0) {
        throw badRequestError("No valid product fields to update");
      }
      const updated = await productRepository.updateProduct(
        entityId as string,
        updateData
      );
      if (!updated) {
        throw notFoundError("Product not found", { productId: entityId });
      }
      return NextResponse.json({
        ok: true,
        entityType,
        entityId,
        updates: updateData,
      });
    }

    if (entityType === "note") {
      ensureAiPathsPermission(access, "notes.manage", "Forbidden.");
      const existing =
        mode === "append" ? await noteService.getById(entityId as string) : null;
      if (mode === "append" && !existing) {
        throw notFoundError("Note not found", { noteId: entityId });
      }
      const prepared =
        mode === "append" && existing
          ? applyAppendMode(normalizedUpdates, existing as Record<string, unknown>)
          : normalizedUpdates;
      const validated = noteUpdateSchema.safeParse(prepared);
      if (!validated.success) {
        throw validationError("Invalid note update", {
          issues: validated.error.flatten(),
        });
      }
      const updateData = removeUndefined(validated.data);
      if (Object.keys(updateData).length === 0) {
        throw badRequestError("No valid note fields to update");
      }
      const updated = await noteService.update(entityId as string, updateData as NoteUpdateInput);
      if (!updated) {
        throw notFoundError("Note not found", { noteId: entityId });
      }
      return NextResponse.json({
        ok: true,
        entityType,
        entityId,
        updates: updateData,
      });
    }

    throw badRequestError("Unsupported entity type");
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.update",
      fallbackMessage: "Failed to update entity",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 { source: "ai-paths.update" });

import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { auth } from "@/features/auth/server";
import { parseJsonBody } from "@/features/products/server";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { conflictError, authError, validationError } from "@/shared/errors/app-error";
import { getAuthSecurityProfile, updateAuthSecurityProfile } from "@/features/auth/server";
import { decryptAuthSecret } from "@/features/auth/server";
import { generateRecoveryCodes, hashRecoveryCode, verifyTotpToken } from "@/features/auth/server";
import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";

export const runtime = "nodejs";

const payloadSchema = z.object({
  token: z.string().trim().min(4),
});

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const session = await auth();
    const userId = session?.user?.id;
    if (!userId) {
      throw authError("Unauthorized.");
    }

    const parsed = await parseJsonBody(req, payloadSchema, {
      logPrefix: "auth.mfa.verify.POST",
    });
    if (!parsed.ok) return parsed.response;

    const profile = await getAuthSecurityProfile(userId);
    if (!profile.mfaSecret) {
      throw conflictError("MFA setup has not been started.");
    }
    if (profile.mfaEnabled) {
      throw conflictError("MFA is already enabled.");
    }

    const secret = decryptAuthSecret(profile.mfaSecret);
    const ok = verifyTotpToken(secret, parsed.data?.token!);
    if (!ok) {
      throw validationError("Invalid MFA token.");
    }

    const recoveryCodes = generateRecoveryCodes(8);
    const hashedCodes = recoveryCodes.map(hashRecoveryCode);
    await updateAuthSecurityProfile(userId, {
      mfaEnabled: true,
      recoveryCodes: hashedCodes,
    });

    return NextResponse.json({
      ok: true,
      recoveryCodes,
    });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "auth.mfa.verify.POST",
      fallbackMessage: "Failed to verify MFA",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 { source: "auth.mfa.verify.POST" });

import { NextRequest, NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import { z } from "zod";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { normalizeAuthEmail } from "@/features/auth/server";
import { auth } from "@/features/auth/server";
import {
  checkLoginAllowed,
  extractClientIp,
  recordLoginFailure,
  recordLoginSuccess,
} from "@/features/auth/server";
import { getAuthSecurityProfile } from "@/features/auth/server";
import { getAuthUserPageSettings } from "@/features/auth/server";
import { parseJsonBody } from "@/features/products/server";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { internalError } from "@/shared/errors/app-error";
import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";

export const runtime = "nodejs";

const payloadSchema = z.object({
  email: z.string().trim().email(),
  password: z.string().min(1),
});

type MongoUserDoc = {
  email?: string | null;
  passwordHash?: string | null;
  emailVerified?: Date | null;
};

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const session = await auth();
    const hasAccess =
      session?.user?.isElevated ||
      session?.user?.permissions?.includes("auth.users.write");
    if (!hasAccess) {
      return NextResponse.json(
        { ok: false, message: "Unauthorized." },
        { status: 401 }
      );
    }
    const parsed = await parseJsonBody(req, payloadSchema, {
      logPrefix: "auth.mock-signin.POST",
    });
    if (!parsed.ok) {
      return parsed.response;
    }

    if (!process.env.MONGODB_URI) {
      throw internalError("MongoDB is not configured.");
    }

    const email = normalizeAuthEmail(parsed.data?.email!);
    const ip = extractClientIp(req);
    const allowed = await checkLoginAllowed({ email, ip });
    if (!allowed.allowed) {
      return NextResponse.json(
        {
          ok: false,
          message: "Too many attempts. Please try again later.",
        },
        { status: 429 }
      );
    }
    const db = await getMongoDb();
    const user = await db
      .collection<MongoUserDoc>("users")
      .findOne({ email }, { projection: { passwordHash: 1, emailVerified: 1 } });

    if (!user?.passwordHash) {
      await recordLoginFailure({ email, ip, request: req });
      return NextResponse.json({
        ok: false,
        message: "User not found or password is not set.",
      });
    }

    const security = await getAuthSecurityProfile(user._id.toString());
    const settings = await getAuthUserPageSettings();

    if (security.bannedAt) {
      await recordLoginFailure({ email, ip, request: req });
      return NextResponse.json({ ok: false, message: "Account is banned." });
    }
    if (security.disabledAt) {
      await recordLoginFailure({ email, ip, request: req });
      return NextResponse.json({ ok: false, message: "Account is disabled." });
    }
    if (settings.requireEmailVerification) {
      if (!user.emailVerified) {
        await recordLoginFailure({ email, ip, request: req });
        return NextResponse.json({ ok: false, message: "Email verification required." });
      }
    }
    if (security.allowedIps.length > 0 && ip) {
      const allowedSet = new Set(security.allowedIps);
      if (!allowedSet.has(ip)) {
        await recordLoginFailure({ email, ip, request: req });
        return NextResponse.json({ ok: false, message: "IP not allowed." });
      }
    }
    if (security.mfaEnabled) {
      return NextResponse.json({ ok: false, message: "MFA is enabled. Use MFA login." });
    }

    const isValid = await bcrypt.compare(parsed.data?.password!, user.passwordHash);
    if (!isValid) {
      await recordLoginFailure({ email, ip, request: req });
    } else {
      await recordLoginSuccess({ email, ip, request: req });
    }
    return NextResponse.json({
      ok: isValid,
      message: isValid ? "Credentials are valid." : "Invalid credentials.",
    });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "auth.mock-signin.POST",
      fallbackMessage: "Failed to verify credentials",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 { source: "auth.mock-signin.POST" });

import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { hash } from "bcryptjs";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { normalizeAuthEmail } from "@/features/auth/server";
import { getAuthSecurityPolicy, validatePasswordStrength } from "@/features/auth/server";
import { getAuthUserPageSettings } from "@/features/auth/server";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { parseJsonBody } from "@/features/products/server";
import { conflictError, internalError, validationError, forbiddenError } from "@/shared/errors/app-error";
import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";

export const runtime = "nodejs";

const registerSchema = z.object({
  email: z.string().trim().email(),
  password: z.string().min(8),
  name: z.string().trim().min(1).optional(),
  emailVerified: z.boolean().optional(),
});

type MongoUserDoc = {
  email: string;
  name?: string | null;
  passwordHash: string;
  emailVerified: Date | null;
  image?: string | null;
  createdAt: Date;
  updatedAt: Date;
};

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const parsed = await parseJsonBody(req, registerSchema, {
      logPrefix: "auth.register.POST",
    });
    if (!parsed.ok) {
      return parsed.response;
    }
    const data = parsed.data!;
    const pageSettings = await getAuthUserPageSettings();
    if (!pageSettings.allowSignup) {
      throw forbiddenError("Registration is disabled.");
    }
    const policy = await getAuthSecurityPolicy();
    const passwordCheck = validatePasswordStrength(data.password, policy);
    if (!passwordCheck.ok) {
      throw validationError("Password does not meet security policy.", {
        issues: passwordCheck.errors,
      });
    }
    const email = normalizeAuthEmail(data.email);
    const passwordHash = await hash(data.password, 12);

    if (!process.env.MONGODB_URI) {
      throw internalError("MongoDB is not configured.");
    }
    const db = await getMongoDb();
    const existing = await db
      .collection<MongoUserDoc>("users")
      .findOne({ email });
    if (existing) {
      throw conflictError("User already exists.", { email });
    }
    const now = new Date();
    const doc: MongoUserDoc = {
      email,
      name: data.name ?? null,
      passwordHash,
      emailVerified: data.emailVerified ? now : null,
      image: null,
      createdAt: now,
      updatedAt: now,
    };
    const result = await db.collection<MongoUserDoc>("users").insertOne(doc);
    return NextResponse.json(
      { id: result.insertedId.toString(), email: doc.email, name: doc.name },
      { status: 201 }
    );
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "auth.register.POST",
      fallbackMessage: "Failed to register user",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 { source: "auth.register.POST" });

