                      </Button>
                    ) : null}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </SectionPanel>
      {selectedAgentRunId ? (
        <AppModal
          open={true}
          onOpenChange={(open: boolean) => !open && closeAgentModal()}
          title="Agent job details"
