                          ? " · needs input"
                          : ""}
                      </div>
                      {selectedAgentRun.checkpointedAt ? (
                        <div className="mt-2 rounded-md border border-emerald-500/20 bg-emerald-500/5 p-2 text-[11px] text-emerald-200">
