"use client";

import { Button, Input } from "@/shared/ui";
import { useEffect, useState } from "react";
import { IntegrationConnection } from "@/features/integrations/types/integrations-ui";
import { useSettings, useUpdateSetting } from "@/shared/hooks/useSettings";

type BaselinkerSettingsProps = {
  activeConnection: IntegrationConnection | null;
  onTest: () => void;
  isTesting: boolean;
};

export function BaselinkerSettings({
  activeConnection,
  onTest,
  isTesting,
}: BaselinkerSettingsProps): React.JSX.Element {
  const baselinkerConnected = Boolean(activeConnection?.hasBaseApiToken);
  const baseTokenUpdatedAt = activeConnection?.baseTokenUpdatedAt
    ? new Date(activeConnection.baseTokenUpdatedAt).toLocaleString()
    : "—";

  const settingsQuery = useSettings();
  const updateSettingMutation = useUpdateSetting();

  const [syncIntervalMinutes, setSyncIntervalMinutes] = useState("10");
  const [syncMessage, setSyncMessage] = useState<string | null>(null);

  useEffect(() => {
    if (settingsQuery.data) {
      const found = settingsQuery.data.find((setting) => setting.key === "base_sync_poll_interval_minutes");
      if (found?.value) {
        setSyncIntervalMinutes(found.value);
      }
    }
  }, [settingsQuery.data]);

  const handleSaveSyncInterval = async (): Promise<void> => {
    const parsed = Number(syncIntervalMinutes);
    if (!Number.isFinite(parsed) || parsed <= 0) {
      setSyncMessage("Enter a valid number of minutes.");
      return;
    }
    setSyncMessage(null);
    try {
      await updateSettingMutation.mutateAsync({
        key: "base_sync_poll_interval_minutes",
        value: String(parsed),
      });
      setSyncMessage("Sync interval saved.");
    } catch {
      setSyncMessage("Failed to save sync interval.");
    }
  };

  return (
    <div className="space-y-4 rounded-lg border border-border bg-card/60 p-4 text-sm text-gray-200">
      <div>
        <h3 className="text-sm font-semibold text-white">Baselinker API</h3>
        <p className="mt-1 text-xs text-gray-400">
          Enter your Baselinker API token in the connection fields, then test the
          connection to verify it works.
        </p>
      </div>
      {!activeConnection ? (
        <div className="rounded-md border border-dashed border-border p-4 text-xs text-gray-400">
          Add a connection first to enable Baselinker API access.
        </div>
      ) : (
        <div className="space-y-3">
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
            <div className="flex items-center justify-between">
              <span>Connection status</span>
              <span
                className={`rounded-full px-2 py-0.5 text-[10px] font-semibold ${
                  baselinkerConnected
                    ? "bg-emerald-500/20 text-emerald-200"
                    : "bg-amber-500/20 text-amber-200"
                }`}
              >
                {baselinkerConnected ? "Connected" : "Not tested"}
              </span>
            </div>
            <p className="mt-2">
              <span className="text-gray-400">Last verified:</span>{" "}
              {baseTokenUpdatedAt}
            </p>
            {activeConnection.baseLastInventoryId && (
              <p className="mt-1">
                <span className="text-gray-400">Last inventory:</span>{" "}
                {activeConnection.baseLastInventoryId}
              </p>
            )}
          </div>
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
            <div className="flex items-center justify-between">
              <span>Listing sync interval</span>
              {settingsQuery.isLoading ? (
                <span className="text-[10px] text-gray-500">Loading...</span>
              ) : (
                <span className="text-[10px] text-gray-500">Minutes</span>
              )}
            </div>
            <div className="mt-2 flex flex-wrap items-center gap-2">
              <Input
                type="number"
                min="1"
                value={syncIntervalMinutes}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void => setSyncIntervalMinutes(event.target.value)}
                className="w-32 rounded-md border border-border bg-gray-900 px-2 py-1 text-xs text-white"
              />
              <Button
                type="button"
                onClick={(): void => { void handleSaveSyncInterval(); }}
                disabled={updateSettingMutation.isPending}
                className="rounded-md bg-white px-3 py-1.5 text-xs font-semibold text-gray-900 hover:bg-gray-200 disabled:opacity-50"
              >
                {updateSettingMutation.isPending ? "Saving..." : "Save"}
              </Button>
            </div>
            <p className="mt-2 text-[10px] text-gray-400">
              Controls how often Base.com is checked for listing status updates.
            </p>
            {syncMessage && (
              <p className="mt-2 text-[10px] text-gray-400">{syncMessage}</p>
            )}
          </div>
          <div className="flex flex-wrap items-center gap-3">
            <Button
              type="button"
              onClick={onTest}
              disabled={isTesting}
              className="rounded-md bg-white px-3 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200 disabled:opacity-50"
            >
              {isTesting
                ? "Testing..."
                : baselinkerConnected
                ? "Re-test Connection"
                : "Test Connection"}
            </Button>
          </div>
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-400">
            <p>
              To get your API token, log in to{" "}
              <a
                href="https://baselinker.com"
                target="_blank"
                rel="noopener noreferrer"
                className="text-purple-300 hover:text-purple-200"
              >
                Baselinker
              </a>{" "}
              → My Account → API.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { Tabs, TabsContent, TabsList, TabsTrigger, Button, Card, ModalShell, AppModal, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/shared/ui";
import { Dispatch, SetStateAction, useState, useEffect } from "react";

import {
  Integration,
  IntegrationConnection,
  TestLogEntry,
} from "@/features/integrations/types/integrations-ui";
import { ConnectionManager } from "./ConnectionManager";
import type { PlaywrightPersona, PlaywrightSettings } from "@/features/playwright";
import { BaseApiConsole } from "./BaseApiConsole";
import { AllegroApiConsole } from "./AllegroApiConsole";
import { AllegroSettings } from "./AllegroSettings";
import { BaselinkerSettings } from "./BaselinkerSettings";
import { TestLogModal } from "./TestLogModal";
import { TestErrorModal } from "./TestErrorModal";
import { TestSuccessModal } from "./TestSuccessModal";
import { SessionModal } from "./SessionModal";




import Link from "next/link";

type PlaywrightSettingsFormProps = {
  settings: PlaywrightSettings;
  setSettings: Dispatch<SetStateAction<PlaywrightSettings>>;
  onSave: () => void;
};

function DynamicPlaywrightSettingsForm(props: PlaywrightSettingsFormProps) {
  const [Component, setComponent] = useState<React.ComponentType<PlaywrightSettingsFormProps> | null>(null);

  useEffect(() => {
    const loadComponent = async () => {
      const { PlaywrightSettingsForm } = await import("@/features/playwright");
      setComponent(() => PlaywrightSettingsForm);
    };
    loadComponent();
  }, []);

  if (!Component) {
    return <div className="p-4 text-gray-400">Loading...</div>;
  }

  return <Component {...props} />;
}


type IntegrationModalProps = {
  activeIntegration: Integration;
  connections: IntegrationConnection[];
  onClose: () => void;

  // Connection Manager
  editingConnectionId: string | null;
  setEditingConnectionId: (id: string | null) => void;
  connectionForm: { name: string; username: string; password: string };
  setConnectionForm: Dispatch<
    SetStateAction<{ name: string; username: string; password: string }>
  >;
  onSaveConnection: () => void;
  onDeleteConnection: (connection: IntegrationConnection) => void;
  onTestConnection: (connection: IntegrationConnection) => void;
  onBaselinkerTest: (connection: IntegrationConnection) => void;
  onAllegroTest: (connection: IntegrationConnection) => void;
  isTesting: boolean;
  testLog: TestLogEntry[];
  onShowLog: (step: TestLogEntry) => void;

  // Modals State
  showTestLogModal: boolean;
  onCloseTestLogModal: () => void;
  selectedStep: (TestLogEntry & { status: "ok" | "failed" }) | null;

  showTestErrorModal: boolean;
  testError: string | null;
  testErrorMeta: {
    errorId?: string | undefined;
    integrationId?: string | null | undefined;
    connectionId?: string | null | undefined;
  } | null;
  onCloseTestErrorModal: () => void;

  showTestSuccessModal: boolean;
  testSuccessMessage: string | null;
  onCloseTestSuccessModal: () => void;

  showSessionModal: boolean;
  sessionLoading: boolean;
  sessionError: string | null;
  sessionCookies: {
    name?: string;
    value?: string;
    domain?: string;
    path?: string;
    expires?: number;
    httpOnly?: boolean;
    secure?: boolean;
    sameSite?: string;
  }[];
  sessionOrigins: {
    origin?: string;
    localStorage?: { name?: string; value?: string }[];
  }[];
  sessionUpdatedAt: string | null;
  onCloseSessionModal: () => void;

  // Playwright
  playwrightPersonas: PlaywrightPersona[];
  playwrightPersonasLoading: boolean;
  playwrightPersonaId: string | null;
  onSelectPlaywrightPersona: (personaId: string | null) => void;
  playwrightSettings: PlaywrightSettings;
  setPlaywrightSettings: Dispatch<
    SetStateAction<PlaywrightSettings>
  >;
  onSavePlaywrightSettings: () => void;
  showPlaywrightSaved: boolean;
  onOpenSessionModal: () => void;

  // Allegro Settings
  savingAllegroSandbox: boolean;
  onToggleAllegroSandbox: (checked: boolean) => void;
  onAllegroAuthorize: () => void;
  onAllegroDisconnect: () => void;
  onAllegroSandboxConnect: () => void;

  // Base API Console
  baseApiMethod: string;
  setBaseApiMethod: (value: string) => void;
  baseApiParams: string;
  setBaseApiParams: (value: string) => void;
  baseApiLoading: boolean;
  baseApiError: string | null;
  baseApiResponse: { data: unknown } | null;
  onBaseApiRequest: () => void;

  // Allegro API Console
  allegroApiMethod: string;
  setAllegroApiMethod: (value: string) => void;
  allegroApiPath: string;
  setAllegroApiPath: (value: string) => void;
  allegroApiBody: string;
  setAllegroApiBody: (value: string) => void;
  allegroApiLoading: boolean;
  allegroApiError: string | null;
  allegroApiResponse: {
    status: number;
    statusText: string;
    data: unknown;
    refreshed?: boolean | undefined;
  } | null;
  onAllegroApiRequest: () => void;
};

export function IntegrationModal({
  activeIntegration,
  connections,
  onClose,
  editingConnectionId,
  setEditingConnectionId,
  connectionForm,
  setConnectionForm,
  onSaveConnection,
  onDeleteConnection,
  onTestConnection,
  onBaselinkerTest,
  onAllegroTest,
  isTesting,
  testLog,
  onShowLog,
  showTestLogModal,
  onCloseTestLogModal,
  selectedStep,
  showTestErrorModal,
  testError,
  testErrorMeta,
  onCloseTestErrorModal,
  showTestSuccessModal,
  testSuccessMessage,
  onCloseTestSuccessModal,
  showSessionModal,
  sessionLoading,
  sessionError,
  sessionCookies,
  sessionOrigins,
  sessionUpdatedAt,
  onCloseSessionModal,
  playwrightPersonas,
  playwrightPersonasLoading,
  playwrightPersonaId,
  onSelectPlaywrightPersona,
  playwrightSettings,
  setPlaywrightSettings,
  onSavePlaywrightSettings,
  showPlaywrightSaved,
  onOpenSessionModal,
  savingAllegroSandbox,
  onToggleAllegroSandbox,
  onAllegroAuthorize,
  onAllegroDisconnect,
  onAllegroSandboxConnect,
  baseApiMethod,
  setBaseApiMethod,
  baseApiParams,
  setBaseApiParams,
  baseApiLoading,
  baseApiError,
  baseApiResponse,
  onBaseApiRequest,
  allegroApiMethod,
  setAllegroApiMethod,
  allegroApiPath,
  setAllegroApiPath,
  allegroApiBody,
  setAllegroApiBody,
  allegroApiLoading,
  allegroApiError,
  allegroApiResponse,
  onAllegroApiRequest,
}: IntegrationModalProps): React.JSX.Element {
  const [activeTab, setActiveTab] = useState("connections");
  const integrationSlug = activeIntegration.slug;
  const isTradera = integrationSlug === "tradera";
  const isAllegro = integrationSlug === "allegro";
  const isBaselinker = integrationSlug === "baselinker";
  const showPlaywright = isTradera;
  const showAllegroConsole = isAllegro;
  const showBaseConsole = isBaselinker;
  const activeConnection = connections[0] || null;
  const selectedPersona =
    playwrightPersonas.find((persona: PlaywrightPersona) => persona.id === playwrightPersonaId) ??
    null;

  const header = (
    <div className="flex items-center justify-between">
      <div className="flex items-center gap-4">
        {activeTab === "playwright" && (
          <Button
            onClick={onSavePlaywrightSettings}
            className="min-w-[100px] border border-white/20 hover:border-white/40"
          >
            Save
          </Button>
        )}
        <h2 className="text-2xl font-bold text-white">
          {activeIntegration.name} Integration
          {isTradera && (
            <span className="ml-2 rounded bg-orange-500/30 px-1.5 py-0.5 text-xs font-normal uppercase tracking-wider text-orange-200">
              Browser
            </span>
          )}
          {isAllegro && (
            <span className="ml-2 rounded bg-blue-500/30 px-1.5 py-0.5 text-xs font-normal uppercase tracking-wider text-blue-200">
              API
            </span>
          )}
          {isBaselinker && (
            <span className="ml-2 rounded bg-purple-500/30 px-1.5 py-0.5 text-xs font-normal uppercase tracking-wider text-purple-200">
              Platform
            </span>
          )}
        </h2>
      </div>
      <Button
        type="button"
        onClick={onClose}
        className="min-w-[100px] border border-white/20 hover:border-white/40"
      >
        Close
      </Button>
    </div>
  );

  return (
    <AppModal
      open={true}
      onOpenChange={(open: boolean): void => { if (!open) onClose(); }}
      title={`${activeIntegration.name} Integration`}
    >
      <ModalShell
        title={`${activeIntegration.name} Integration`}
        onClose={onClose}
        header={header}
      >
        <div className="mb-4">
          <p className="text-sm text-gray-400">
            {isBaselinker
              ? "Manage connections and warehouse sync settings."
              : isTradera
              ? "Manage connections via browser automation (Playwright)."
              : "Manage connections and marketplace API settings."}
          </p>
        </div>

          <Tabs defaultValue="connections" value={activeTab} onValueChange={setActiveTab}>
            <TabsList
              className={`grid w-full ${
                showPlaywright || showAllegroConsole || showBaseConsole
                  ? "grid-cols-5"
                  : "grid-cols-4"
              }`}
            >
              <TabsTrigger value="connections">Connections</TabsTrigger>
              <TabsTrigger value="settings">Settings</TabsTrigger>
              {showAllegroConsole && (
                <TabsTrigger value="allegro-api">Allegro API</TabsTrigger>
              )}
              {showBaseConsole && (
                <TabsTrigger value="base-api">Base API</TabsTrigger>
              )}
              <TabsTrigger value="price-sync">Price Sync</TabsTrigger>
              <TabsTrigger value="inventory-sync">Inventory Sync</TabsTrigger>
              {showPlaywright && (
                <TabsTrigger value="playwright">Playwright</TabsTrigger>
              )}
            </TabsList>

            <TabsContent value="connections" className="mt-4 space-y-6">
              <ConnectionManager
                activeIntegration={activeIntegration}
                connections={connections}
                editingConnectionId={editingConnectionId}
                setEditingConnectionId={setEditingConnectionId}
                connectionForm={connectionForm}
                setConnectionForm={setConnectionForm}
                onSave={onSaveConnection}
                onDelete={onDeleteConnection}
                onTest={(conn: IntegrationConnection): void => {
                  if (isBaselinker) onBaselinkerTest(conn);
                  else if (isAllegro) onAllegroTest(conn);
                  else onTestConnection(conn);
                }}
                isTesting={isTesting}
                testLog={testLog}
                onShowLog={onShowLog}
              />
            </TabsContent>

            <TabsContent value="settings" className="mt-4">
              {isAllegro ? (
                <AllegroSettings
                  activeConnection={activeConnection}
                  savingSandbox={savingAllegroSandbox}
                  onToggleSandbox={onToggleAllegroSandbox}
                  onAuthorize={onAllegroAuthorize}
                  onDisconnect={onAllegroDisconnect}
                  onSandboxConnect={onAllegroSandboxConnect}
                />
              ) : isBaselinker ? (
                <BaselinkerSettings
                  activeConnection={activeConnection}
                  onTest={(): void => {
                    if (activeConnection) onBaselinkerTest(activeConnection);
                  }}
                  isTesting={isTesting}
                />
              ) : (
                <div className="min-h-[220px]" />
              )}

              {isTradera && activeConnection && (
                <div className="mt-4 rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
                  <div className="flex items-center justify-between gap-3">
                    <p>
                      <span className="text-gray-400">Session cookie:</span>{" "}
                      {activeConnection.hasPlaywrightStorageState
                        ? "Retained"
                        : "Not stored"}
                    </p>
                    <Button
                      type="button"
                      onClick={onOpenSessionModal}
                      disabled={!activeConnection.hasPlaywrightStorageState}
                      className="text-xs text-emerald-200 hover:text-emerald-100 disabled:cursor-not-allowed disabled:text-gray-600"
                    >
                      View details
                    </Button>
                  </div>
                  <p className="mt-1">
                    <span className="text-gray-400">Obtained:</span>{" "}
                    {activeConnection.playwrightStorageStateUpdatedAt
                      ? new Date(
                          activeConnection.playwrightStorageStateUpdatedAt
                        ).toLocaleString()
                      : "—"}
                  </p>
                </div>
              )}
            </TabsContent>

            {showBaseConsole && (
              <TabsContent value="base-api" className="mt-4">
                <BaseApiConsole
                  activeConnection={activeConnection}
                  method={baseApiMethod}
                  setMethod={setBaseApiMethod}
                  params={baseApiParams}
                  setParams={setBaseApiParams}
                  loading={baseApiLoading}
                  error={baseApiError}
                  response={baseApiResponse}
                  onRequest={onBaseApiRequest}
                />
              </TabsContent>
            )}

            {showAllegroConsole && (
              <TabsContent value="allegro-api" className="mt-4">
                <AllegroApiConsole
                  activeConnection={activeConnection}
                  method={allegroApiMethod}
                  setMethod={setAllegroApiMethod}
                  path={allegroApiPath}
                  setPath={setAllegroApiPath}
                  body={allegroApiBody}
                  setBody={setAllegroApiBody}
                  loading={allegroApiLoading}
                  error={allegroApiError}
                  response={
                    allegroApiResponse
                      ? {
                          status: allegroApiResponse.status,
                          statusText: allegroApiResponse.statusText,
                          data: allegroApiResponse.data,
                          ...(allegroApiResponse.refreshed !== undefined && {
                            refreshed: allegroApiResponse.refreshed,
                          }),
                        }
                      : null
                  }
                  onRequest={onAllegroApiRequest}
                  isConnected={Boolean(activeConnection?.hasAllegroAccessToken)}
                />
              </TabsContent>
            )}

            <TabsContent value="price-sync" className="mt-4">
              <div className="min-h-[220px]" />
            </TabsContent>
            <TabsContent value="inventory-sync" className="mt-4">
              <div className="min-h-[220px]" />
            </TabsContent>

            {showPlaywright && (
              <TabsContent value="playwright" className="mt-4 space-y-4">
                <Card className="border-border bg-card/60 p-4">
                  <div className="flex flex-wrap items-center justify-between gap-3">
                    <div>
                      <p className="text-sm font-semibold text-white">
                        Playwright persona
                      </p>
                      <p className="mt-1 text-xs text-gray-400">
                        Apply shared automation presets to this connection.
                      </p>
                    </div>
                    <Button variant="outline" size="sm" asChild>
                      <Link href="/admin/settings/playwright">
                        Manage personas
                      </Link>
                    </Button>
                  </div>

                  {playwrightPersonasLoading ? (
                    <p className="mt-4 text-xs text-gray-500">
                      Loading personas...
                    </p>
                  ) : playwrightPersonas.length === 0 ? (
                    <p className="mt-4 text-xs text-gray-500">
                      No personas yet. Create one in settings.
                    </p>
                  ) : (
                    <div className="mt-4 grid gap-4 md:grid-cols-2">
                      <div className="space-y-2">
                        <Label className="text-xs text-gray-400">
                          Persona
                        </Label>
                        <Select
                          value={playwrightPersonaId ?? "custom"}
                          onValueChange={(value: string): void =>
                            onSelectPlaywrightPersona(
                              value === "custom" ? null : value
                            )
                          }
                        >
                          <SelectTrigger>
                            <SelectValue placeholder="Select persona" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="custom">Custom</SelectItem>
                            {playwrightPersonas.map((persona: PlaywrightPersona) => (
                              <SelectItem key={persona.id} value={persona.id}>
                                {persona.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <p className="text-[11px] text-gray-500">
                          Selecting a persona overwrites the settings below.
                        </p>
                      </div>
                      <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-400">
                        {selectedPersona ? (
                          <>
                            <p className="text-xs font-semibold text-gray-200">
                              {selectedPersona.name}
                            </p>
                            <p className="mt-1">
                              {selectedPersona.description ||
                                "No description provided."}
                            </p>
                          </>
                        ) : (
                          <>
                            <p className="text-xs font-semibold text-gray-200">
                              Custom settings
                            </p>
                            <p className="mt-1">
                              Adjust the form below or apply a persona.
                            </p>
                          </>
                        )}
                      </div>
                    </div>
                  )}
                </Card>

                <DynamicPlaywrightSettingsForm
                  settings={playwrightSettings}
                  setSettings={setPlaywrightSettings}
                  onSave={onSavePlaywrightSettings}
                />
              </TabsContent>
            )}
          </Tabs>
        </ModalShell>

        {showTestLogModal && selectedStep && (
          <TestLogModal selectedStep={selectedStep} onClose={onCloseTestLogModal} />
        )}

        {showTestErrorModal && testError && (
          <TestErrorModal
            testError={testError}
            testErrorMeta={
              testErrorMeta
                ? {
                    ...(testErrorMeta.errorId !== undefined && {
                      errorId: testErrorMeta.errorId,
                    }),
                    ...(testErrorMeta.integrationId !== undefined && {
                      integrationId: testErrorMeta.integrationId,
                    }),
                    ...(testErrorMeta.connectionId !== undefined && {
                      connectionId: testErrorMeta.connectionId,
                    }),
                  }
                : null
            }
            onClose={onCloseTestErrorModal}
          />
        )}

        {showTestSuccessModal && testSuccessMessage && (
          <TestSuccessModal
            message={testSuccessMessage}
            onClose={onCloseTestSuccessModal}
          />
        )}

        {showSessionModal && (
          <SessionModal
            loading={sessionLoading}
            error={sessionError}
            cookies={sessionCookies}
            origins={sessionOrigins}
            updatedAt={sessionUpdatedAt}
            onClose={onCloseSessionModal}
          />
        )}
        {showPlaywrightSaved && (
          <div className="fixed right-6 top-6 z-[200] rounded-md border border-emerald-400/40 bg-emerald-500/20 px-3 py-2 text-xs font-medium text-emerald-100 shadow-lg">
            Playwright settings saved
          </div>
        )}
    </AppModal>
  );
}

"use client";
import { Button, Label, DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, ModalShell, Checkbox, useToast } from "@/shared/ui";
import { useState } from "react";
import { useMutation } from "@tanstack/react-query";

import type { ProductWithImages } from "@/features/products";
import type {
  ImageRetryPreset,
  Template,
  BaseInventory,
} from "@/features/data-import-export";
import { ExportLogViewer } from "./ExportLogViewer";
import type { CapturedLog } from "@/features/integrations/services/exports/log-capture";
import { useImageRetryPresets } from "./useImageRetryPresets";

import { useIntegrationSelection } from "./hooks/useIntegrationSelection";
import { useBaseComSettings } from "./hooks/useBaseComSettings";
import { isImageExportError } from "./utils";
import { useProducts } from "@/features/products/hooks/useProductsQuery";

type SelectProductForListingModalProps = {
  integrationId: string;
  connectionId: string;
  onClose: () => void;
  onSuccess: () => void;
};

export default function SelectProductForListingModal({
  integrationId: initialIntegrationId,
  connectionId: initialConnectionId,
  onClose,
  onSuccess,
}: SelectProductForListingModalProps): React.JSX.Element {
  const [error, setError] = useState<string | null>(null);
  const [selectedProductId, setSelectedProductId] = useState<string>("");
  const [submitting, setSubmitting] = useState(false);
  const { toast } = useToast();

  const { data: products = [] } = useProducts({ pageSize: 1000 });

  // Integration & connection selection
  const {
    loading: loadingIntegrations,
    selectedIntegrationId,
    selectedConnectionId,
    selectedIntegration,
    isBaseComIntegration,
  } = useIntegrationSelection(initialIntegrationId, initialConnectionId);

  // Base.com specific settings
  const {
    templates,
    selectedTemplateId,
    setSelectedTemplateId,
    inventories,
    selectedInventoryId,
    setSelectedInventoryId,
    loadingInventories,
    allowDuplicateSku,
    setAllowDuplicateSku,
  } = useBaseComSettings(isBaseComIntegration, selectedConnectionId);

  // Export logging
  const [exportLogs, setExportLogs] = useState<CapturedLog[]>([]);
  const [logsOpen, setLogsOpen] = useState(false);
  const imageRetryPresets = useImageRetryPresets();

  const connectionName = (selectedIntegration?.connections as Array<{ id: string; name: string }>)?.find(
    (c: { id: string; name: string }) => c.id === selectedConnectionId
  )?.name || "";

  const exportMutation = useMutation({
    mutationFn: async ({ productId, payload }: { productId: string; payload: any }) => {
      const res = await fetch(`/api/integrations/products/${productId}/export-to-base`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      const data = await res.json();
      if (!res.ok) {
        throw new Error(data.error || "Failed to export product");
      }
      return data;
    }
  });

  const createListingMutation = useMutation({
    mutationFn: async ({ productId, payload }: { productId: string; payload: any }) => {
      const res = await fetch(`/api/integrations/products/${productId}/listings`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (!res.ok) {
        const data = (await res.json()) as { error?: string };
        throw new Error(data.error || "Failed to create listing");
      }
      return res.json();
    }
  });

  const handleSubmit = async (): Promise<void> => {
    if (!selectedProductId) {
      setError("Please select a product");
      return;
    }

    if (!selectedConnectionId) {
      setError("Please select an account");
      return;
    }

    if (isBaseComIntegration && !selectedInventoryId) {
      setError("Please select a Base.com inventory");
      return;
    }

    try {
      setSubmitting(true);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);

      if (isBaseComIntegration) {
        const payload = {
          connectionId: selectedConnectionId,
          inventoryId: selectedInventoryId,
          templateId: selectedTemplateId !== "none" ? selectedTemplateId : undefined,
          allowDuplicateSku,
        };
        const result = await exportMutation.mutateAsync({ productId: selectedProductId, payload });
        if (result.logs) setExportLogs(result.logs);
        toast("Product exported to Base.com", { variant: "success" });
        onSuccess();
      } else {
        await createListingMutation.mutateAsync({
          productId: selectedProductId,
          payload: {
            integrationId: selectedIntegrationId,
            connectionId: selectedConnectionId,
          }
        });
        toast("Product listing created", { variant: "success" });
        onSuccess();
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to list product");
      if (err instanceof Error && (err as any).logs) {
        setExportLogs((err as any).logs);
      }
    } finally {
      setSubmitting(false);
    }
  };

  const handleImageRetry = async (preset: ImageRetryPreset): Promise<void> => {
    if (!selectedProductId || !isBaseComIntegration || !selectedInventoryId) {
      return;
    }
    try {
      setSubmitting(true);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);

      const payload = {
        connectionId: selectedConnectionId,
        inventoryId: selectedInventoryId,
        templateId: selectedTemplateId !== "none" ? selectedTemplateId : undefined,
        allowDuplicateSku,
        imageBase64Mode: preset.imageBase64Mode,
        imageTransform: preset.transform,
        exportImagesAsBase64: true,
      };

      const result = await exportMutation.mutateAsync({ productId: selectedProductId, payload });
      if (result.logs) setExportLogs(result.logs);
      toast("Product exported with new image settings", { variant: "success" });
      onSuccess();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to export product");
    } finally {
      setSubmitting(false);
    }
  };

  const getProductDisplayName = (product: ProductWithImages): string => {
    return product.name_en || product.name_pl || product.name_de || product.sku || "Unnamed product";
  };

  const loading = loadingIntegrations;

  return (
    <ModalShell
      title={`List Product to ${selectedIntegration?.name || "Marketplace"}`}
      onClose={onClose}
      size="md"
      showClose={false}
      footer={
        <>
          <Button
            variant="outline"
            onClick={onClose}
            className="bg-gray-800 text-white hover:bg-gray-700"
          >
            Cancel
          </Button>
          <Button
            onClick={(): void => { void handleSubmit(); }}
            disabled={
              submitting ||
              !selectedProductId ||
              (isBaseComIntegration && !selectedInventoryId)
            }
          >
            {submitting
              ? isBaseComIntegration
                ? "Exporting..."
                : "Listing..."
              : isBaseComIntegration
              ? "Export to Base.com"
              : "List Product"}
          </Button>
        </>
      }
    >
      <div className="space-y-6">
        {error && (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
            <div className="flex flex-col gap-3">
              <span>{error}</span>
              {isBaseComIntegration && isImageExportError(error) ? (
                <div className="flex flex-wrap items-center gap-2">
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="secondary"
                        size="sm"
                        className="bg-red-500/20 text-red-100 hover:bg-red-500/30"
                        disabled={submitting}
                      >
                        Retry image export
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="start" className="bg-card border-border">
                      {imageRetryPresets.map((preset: ImageRetryPreset) => (
                        <DropdownMenuItem
                          key={preset.id}
                          onSelect={(): void => { void handleImageRetry(preset); }}
                          className="text-gray-200 focus:bg-gray-800/70"
                        >
                          <div className="flex flex-col">
                            <span className="text-sm">{preset.label}</span>
                            <span className="text-xs text-gray-400">
                              {preset.description}
                            </span>
                          </div>
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                  <span className="text-xs text-red-200/80">
                    Applies JPEG resize/compression and retries automatically.
                  </span>
                </div>
              ) : null}
            </div>
          </div>
        )}

        <div className="rounded-md border bg-card/50 px-4 py-3">
          <p className="text-sm text-gray-300">
            <span className="text-gray-500">Integration:</span>{" "}
            <span className="font-medium">{selectedIntegration?.name || "Loading..."}</span>
          </p>
          <p className="text-sm text-gray-300">
            <span className="text-gray-500">Account:</span>{" "}
            <span className="font-medium">{connectionName || "Loading..."}</span>
          </p>
        </div>

        {loading ? (
          <p className="text-sm text-gray-400">Loading products...</p>
        ) : (
          <>
            <div className="space-y-2">
              <Label htmlFor="product">Select Product</Label>
              <Select
                value={selectedProductId}
                onValueChange={setSelectedProductId}
              >
                <SelectTrigger id="product">
                  <SelectValue placeholder="Select a product..." />
                </SelectTrigger>
                <SelectContent>
                  {products.map((product: ProductWithImages) => (
                    <SelectItem key={product.id} value={product.id}>
                      {getProductDisplayName(product)} ({product.sku})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {isBaseComIntegration && (
              <>
                <div className="space-y-2">
                  <Label htmlFor="inventory">
                    Base.com Inventory {loadingInventories && "(Loading...)"}
                  </Label>
                  <Select
                    value={selectedInventoryId}
                    onValueChange={setSelectedInventoryId}
                    disabled={loadingInventories || inventories.length === 0}
                  >
                    <SelectTrigger id="inventory">
                      <SelectValue placeholder="Select inventory..." />
                    </SelectTrigger>
                    <SelectContent>
                      {inventories
                        .filter((inventory: BaseInventory): boolean => !!inventory.id)
                        .map((inventory: BaseInventory) => (
                          <SelectItem key={inventory.id} value={inventory.id}>
                            {inventory.name}
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                  {inventories.length === 0 && !loadingInventories && (
                    <p className="text-xs text-red-400">
                      No inventories found. Please check your Base.com account.
                    </p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="template">Template (Optional)</Label>
                  <Select
                    value={selectedTemplateId}
                    onValueChange={setSelectedTemplateId}
                  >
                    <SelectTrigger id="template">
                      <SelectValue placeholder="No template (use defaults)" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">No template</SelectItem>
                      {templates
                        .filter((template: Template): boolean => !!template.id)
                        .map((template: Template) => (
                          <SelectItem key={template.id} value={template.id}>
                            {template.name}
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-gray-500">
                    Templates define how product fields map to Base.com fields.
                  </p>
                </div>

                <div className="flex items-center gap-2 pt-2">
                  <Checkbox
                    id="allowDuplicateSku"
                    checked={allowDuplicateSku} 
                    onCheckedChange={(checked: boolean | "indeterminate"): void => setAllowDuplicateSku(Boolean(checked))}
                    className="h-4 w-4 rounded border bg-gray-900 text-blue-500"
                  />
                  <Label htmlFor="allowDuplicateSku" className="text-sm text-gray-300">
                    Allow duplicate SKUs
                  </Label>
                </div>
                <p className="text-xs text-gray-500">
                  When unchecked, export will fail if the SKU already exists in the Base.com inventory.
                </p>
              </>
            )}
          </>
        )}
        {exportLogs.length > 0 && (
          <div className="mt-4 border-t border pt-4">
            <ExportLogViewer
              logs={exportLogs}
              isOpen={logsOpen}
              onToggle={setLogsOpen}
            />
          </div>
        )}
      </div>
    </ModalShell>
  );
}

