                <div className="rounded-md border border-border bg-card/40 p-4">
                  <div className="text-gray-400 font-bold text-xs uppercase mb-3">
                    Run Metadata
                  </div>
                  {((): React.ReactNode => {
                    const meta = getJobMeta(selectedJob);
                    const payload = (meta.payload ?? {}) as any;
