                                <div className="text-gray-500">Role</div>
                                <div>{String((getContextValue(log.context, "user.role") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Route</div>
                                <div>{String((getContextValue(log.context, "route") as string | number | null) ?? "—")}</div>
                              </div>
                              <div>
                                <div className="text-gray-500">Device</div>
                                <div>{String((getContextValue(log.context, "device.platform") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Memory</div>
                                <div>{String((getContextValue(log.context, "device.deviceMemory") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Cores</div>
                                <div>{String((getContextValue(log.context, "device.hardwareConcurrency") as string | number | null) ?? "—")}</div>
                              </div>
                              <div>
                                <div className="text-gray-500">Network</div>
                                <div>{String((getContextValue(log.context, "network.effectiveType") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Downlink</div>
                                <div>{String((getContextValue(log.context, "network.downlink") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">RTT</div>
                                <div>{String((getContextValue(log.context, "network.rtt") as string | number | null) ?? "—")}</div>
                              </div>
                            </div>
                          </div>
                        ) : null}
                        {log.stack && (
                          <pre className="mt-2 whitespace-pre-wrap rounded border border-border bg-card p-2 text-[11px] text-gray-300">
                            {log.stack}
                          </pre>
                        )}
                        {log.context && (
                          <pre className="mt-2 whitespace-pre-wrap rounded border border-border bg-card p-2 text-[11px] text-gray-300">
                            {JSON.stringify(log.context, null, 2)}
                          </pre>
                        )}
                      </details>
                    )}
                  </div>
                ))}
              </div>
            )}
            <div className="flex items-center justify-between gap-3 border-t border-border px-4 py-3">
              <Button
                variant="outline"
                size="sm"
                className="border"
                disabled={page <= 1}
                onClick={() => setPage((prev: number) => Math.max(1, prev - 1))}
              >
                Previous
              </Button>
              <Button
                variant="outline"
                size="sm"
                className="border"
                disabled={page >= totalPages}
                onClick={() => setPage((prev: number) => Math.min(totalPages, prev + 1))}
              >
                Next
              </Button>
            </div>
          </div>
        </div>
      </ListPanel>
    </div>
  );
}

// Client-safe redaction utilities
export const REDACTED_VALUE = "[REDACTED]";

const SENSITIVE_KEYS = [
  "password",
  "token",
  "secret",
  "key",
  "auth",
  "credential",
  "session",
  "cookie",
  "authorization",
  "bearer",
  "api_key",
  "apikey",
  "access_token",
  "refresh_token",
  "private_key",
  "client_secret",
];

export const isSensitiveKey = (key: string): boolean => {
  const lowerKey = key.toLowerCase();
  return SENSITIVE_KEYS.some(sensitive => lowerKey.includes(sensitive));
};

export const truncateString = (str: string, maxLength: number): string => {
  if (str.length <= maxLength) return str;
  return str.slice(0, maxLength) + "...";
};

import { ProductWithImages } from "@/features/products/types";

// This function fetches a list of products from the API.
export async function getProducts(filters: {
  search?: string | undefined;
  sku?: string | undefined;
  minPrice?: number | undefined;
  maxPrice?: number | undefined;
  startDate?: string | undefined;
  endDate?: string | undefined;
  page?: number | undefined;
  pageSize?: number | undefined;
  catalogId?: string | undefined;
  searchLanguage?: string | undefined;
}): Promise<ProductWithImages[]> {
  const query = new URLSearchParams();
  if (filters.search) query.append("search", filters.search);
  if (filters.sku) query.append("sku", filters.sku);
  if (filters.minPrice !== undefined) query.append("minPrice", String(filters.minPrice));
  if (filters.maxPrice !== undefined) query.append("maxPrice", String(filters.maxPrice));
  if (filters.startDate) query.append("startDate", filters.startDate);
  if (filters.endDate) query.append("endDate", filters.endDate);
  if (filters.page) query.append("page", String(filters.page));
  if (filters.pageSize) query.append("pageSize", String(filters.pageSize));
  if (filters.catalogId) query.append("catalogId", filters.catalogId);
  if (filters.searchLanguage) query.append("searchLanguage", filters.searchLanguage);

  const res = await fetch(`/api/products?${query.toString()}`);
  if (!res.ok) {
    let payload: { error?: string; errorId?: string } | null = null;
    try {
      payload = (await res.json()) as { error?: string; errorId?: string };
    } catch {
      payload = null;
    }
    const message = payload?.error || "Failed to fetch products";
    const errorId = payload?.errorId;
    const error = new Error(
      errorId ? `${message} (Error ID: ${errorId})` : message
    );
    (error as { errorId?: string | undefined }).errorId = errorId;
    throw error;
  }
  return res.json() as Promise<ProductWithImages[]>;
}

export async function countProducts(filters: {
  search?: string | undefined;
  sku?: string | undefined;
  minPrice?: number | undefined;
  maxPrice?: number | undefined;
  startDate?: string | undefined;
  endDate?: string | undefined;
  catalogId?: string | undefined;
  searchLanguage?: string | undefined;
}): Promise<number> {
  const query = new URLSearchParams();
  if (filters.search) query.append("search", filters.search);
  if (filters.sku) query.append("sku", filters.sku);
  if (filters.minPrice !== undefined) query.append("minPrice", String(filters.minPrice));
  if (filters.maxPrice !== undefined) query.append("maxPrice", String(filters.maxPrice));
  if (filters.startDate) query.append("startDate", filters.startDate);
  if (filters.endDate) query.append("endDate", filters.endDate);
  if (filters.catalogId) query.append("catalogId", filters.catalogId);
  if (filters.searchLanguage) query.append("searchLanguage", filters.searchLanguage);

  const res = await fetch(`/api/products/count?${query.toString()}`);
  if (!res.ok) {
    throw new Error("Failed to fetch product count");
  }
  const data = (await res.json()) as { count: number };
  return data.count;
}

