"use client";

import { Button, AppModal, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, useToast, Input, Textarea, Label } from "@/shared/ui";
import React, { useState, useCallback, useMemo, useEffect } from "react";
import {
  ChevronRight,
  ChevronDown,
  Plus,
  Trash2,
  FolderPlus,
} from "lucide-react";

import type { ProductCategoryWithChildren, Catalog, ProductCategory } from "@/features/products/types";
import { useSaveCategoryMutation, useDeleteCategoryMutation } from "@/features/products/hooks/useProductSettingsQueries";

type CategoriesSettingsProps = {
  loading: boolean;
  categories: ProductCategoryWithChildren[];
  catalogs: Catalog[];
  selectedCatalogId: string | null;
  onCatalogChange: (catalogId: string) => void;
  onRefresh: () => void;
};

type CategoryNodeProps = {
  category: ProductCategoryWithChildren;
  level: number;
  expandedIds: Set<string>;
  onToggleExpand: (id: string) => void;
  onEdit: (category: ProductCategoryWithChildren) => void;
  onDelete: (category: ProductCategoryWithChildren) => void;
  onCreateChild: (parentId: string) => void;
  draggedId: string | null;
  onDragStart: (id: string) => void;
  onDragEnd: () => void;
  onDrop: (draggedId: string, targetId: string | null) => void;
  allCategories: ProductCategoryWithChildren[];
};

function CategoryNode({
  category,
  level,
  expandedIds,
  onToggleExpand,
  onEdit,
  onDelete,
  onCreateChild,
  draggedId,
  onDragStart,
  onDragEnd,
  onDrop,
  allCategories,
}: CategoryNodeProps): React.JSX.Element {
  const [isDragOver, setIsDragOver] = useState<boolean>(false);
  const hasChildren: boolean = category.children.length > 0;
  const isExpanded: boolean = expandedIds.has(category.id);

  const canDropHere: boolean = useMemo((): boolean => {
    if (!draggedId) return true;
    if (draggedId === category.id) return false;

    // Check if the target category is a descendant of the dragged category
    const isDescendant = (
      cat: ProductCategoryWithChildren,
      targetId: string
    ): boolean => {
      if (cat.id === targetId) return true;
      return cat.children.some((child: ProductCategoryWithChildren): boolean => isDescendant(child, targetId));
    };

    const findCategory = (
      cats: ProductCategoryWithChildren[],
      id: string
    ): ProductCategoryWithChildren | null => {
      for (const cat of cats) {
        if (cat.id === id) return cat;
        const found: ProductCategoryWithChildren | null = findCategory(cat.children, id);
        if (found) return found;
      }
      return null;
    };

    const draggedCategory: ProductCategoryWithChildren | null = findCategory(allCategories, draggedId);
    if (!draggedCategory) return true;

    return !isDescendant(draggedCategory, category.id);
  }, [draggedId, category.id, allCategories]);

  return (
    <div>
      <div
        draggable
        onDragStart={(e: React.DragEvent): void => {
          e.stopPropagation();
          e.dataTransfer.setData("categoryId", category.id);
          e.dataTransfer.effectAllowed = "move";
          onDragStart(category.id);
          const target: HTMLElement = e.currentTarget as HTMLElement;
          target.style.opacity = "0.5";
        }}
        onDragEnd={(e: React.DragEvent): void => {
          const target: HTMLElement = e.currentTarget as HTMLElement;
          target.style.opacity = "1";
          onDragEnd();
        }}
        onDragOver={(e: React.DragEvent): void => {
          e.preventDefault();
          e.stopPropagation();
          if (canDropHere) {
            setIsDragOver(true);
          }
        }}
        onDragLeave={(e: React.DragEvent): void => {
          e.stopPropagation();
          setIsDragOver(false);
        }}
        onDrop={(e: React.DragEvent): void => {
          e.preventDefault();
          e.stopPropagation();
          setIsDragOver(false);
          const droppedId: string = e.dataTransfer.getData("categoryId") || (draggedId ?? "");
          if (droppedId && canDropHere) {
            onDrop(droppedId, category.id);
          }
        }}
        className={`group flex items-center gap-1 rounded px-2 py-1.5 cursor-pointer active:cursor-grabbing transition ${
          isDragOver && canDropHere
            ? "bg-emerald-600 text-white"
            : "text-gray-300 hover:bg-muted/50"
        }`}
        style={{ paddingLeft: `${level * 16 + 8}px` }}
      >
        {hasChildren ? (
          <Button
            onClick={(): void => onToggleExpand(category.id)}
            className="p-0.5 hover:bg-gray-700 rounded"
          >
            {isExpanded ? (
              <ChevronDown className="size-4" />
            ) : (
              <ChevronRight className="size-4" />
            )}
          </Button>
        ) : (
          <div className="w-5" />
        )}

        <div className="flex items-center gap-2 flex-1 min-w-0">
          <span className="text-sm truncate">{category.name}</span>
        </div>

        <div className="flex items-center gap-1">
          <Button
            onClick={(e: React.MouseEvent): void => {
              e.stopPropagation();
              onCreateChild(category.id);
            }}
            className="p-1 hover:bg-gray-700 rounded"
            title="Add subcategory"
          >
            <FolderPlus className="size-3" />
          </Button>
          <Button
            onClick={(e: React.MouseEvent): void => {
              e.stopPropagation();
              onEdit(category);
            }}
            className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-100 hover:bg-gray-700"
            title="Edit category"
          >
            Edit
          </Button>
          <Button
            onClick={(e: React.MouseEvent): void => {
              e.stopPropagation();
              onDelete(category);
            }}
            className="p-1 hover:bg-red-600 rounded"
            title="Delete category"
          >
            <Trash2 className="size-3" />
          </Button>
        </div>
      </div>

      {isExpanded && hasChildren && (
        <div>
          {category.children.map((child: ProductCategoryWithChildren): React.JSX.Element => (
            <CategoryNode
              key={child.id}
              category={child}
              level={level + 1}
              expandedIds={expandedIds}
              onToggleExpand={onToggleExpand}
              onEdit={onEdit}
              onDelete={onDelete}
              onCreateChild={onCreateChild}
              draggedId={draggedId}
              onDragStart={onDragStart}
              onDragEnd={onDragEnd}
              onDrop={onDrop}
              allCategories={allCategories}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export function CategoriesSettings({
  loading,
  categories,
  catalogs,
  selectedCatalogId,
  onCatalogChange,
  onRefresh,
}: CategoriesSettingsProps): React.JSX.Element {
  const { toast } = useToast();
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
  const [draggedId, setDraggedId] = useState<string | null>(null);
  const [showModal, setShowModal] = useState<boolean>(false);
  const [editingCategory, setEditingCategory] =
    useState<ProductCategoryWithChildren | null>(null);
  const [formData, setFormData] = useState({
    name: "",
    description: "",
    color: "#10b981",
    parentId: null as string | null,
    catalogId: "",
  });

  const saveCategoryMutation = useSaveCategoryMutation();
  const deleteCategoryMutation = useDeleteCategoryMutation();

  const [modalCatalogId, setModalCatalogId] = useState<string | null>(null);
  const [modalCategories, setModalCategories] = useState<ProductCategoryWithChildren[]>([]);
  const [modalLoadingCategories, setModalLoadingCategories] = useState<boolean>(false);

  // Reset expanded state when catalog changes
  useEffect((): void => {
    setExpandedIds(new Set());
  }, [selectedCatalogId]);

  // Expand all categories on initial load
  useEffect((): void => {
    if (categories.length > 0 && expandedIds.size === 0) {
      const collectIds = (cats: ProductCategoryWithChildren[]): string[] => {
        const ids: string[] = [];
        for (const cat of cats) {
          ids.push(cat.id);
          if (cat.children.length > 0) {
            ids.push(...collectIds(cat.children));
          }
        }
        return ids;
      };
      setExpandedIds(new Set(collectIds(categories)));
    }
  }, [categories, expandedIds.size]);

  const handleToggleExpand = useCallback((id: string): void => {
    setExpandedIds((prev: Set<string>): Set<string> => {
      const next: Set<string> = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }, []);

  const handleOpenCreateModal = (parentId: string | null = null): void => {
    if (!selectedCatalogId) {
      toast("Please select a catalog first", { variant: "error" });
      return;
    }
    setEditingCategory(null);
    setFormData({
      name: "",
      description: "",
      color: "#10b981",
      parentId,
      catalogId: selectedCatalogId,
    });
    setModalCatalogId(selectedCatalogId);
    setShowModal(true);
  };

  const handleOpenEditModal = (category: ProductCategoryWithChildren): void => {
    setEditingCategory(category);
    setFormData({
      name: category.name,
      description: category.description || "",
      color: category.color || "#10b981",
      parentId: category.parentId ?? null,
      catalogId: category.catalogId,
    });
    setModalCatalogId(category.catalogId);
    setShowModal(true);
  };

  const handleDelete = async (category: ProductCategoryWithChildren): Promise<void> => {
    const hasChildren: boolean = category.children.length > 0;
    const message: string = hasChildren
      ? `Delete category "${category.name}" and all its subcategories? This cannot be undone.`
      : `Delete category "${category.name}"? This cannot be undone.`;

    if (!window.confirm(message)) return;

    try {
      await deleteCategoryMutation.mutateAsync({ id: category.id, catalogId: selectedCatalogId });
      toast("Category deleted successfully", { variant: "success" });
      onRefresh();
    } catch (error) {
      const message: string =
        error instanceof Error ? error.message : "Failed to delete category";
      toast(message, { variant: "error" });
    }
  };

  const handleSave = async (): Promise<void> => {
    if (!formData.name.trim()) {
      toast("Category name is required", { variant: "error" });
      return;
    }

    const targetCatalogId: string | undefined = (formData.catalogId || selectedCatalogId) || undefined;
    if (!targetCatalogId && !editingCategory) {
      toast("Please select a catalog first", { variant: "error" });
      return;
    }

    try {
      const payload: Partial<ProductCategory> = {
        name: formData.name.trim(),
        description: formData.description.trim() || null,
        color: formData.color,
        parentId: formData.parentId ?? null,
        catalogId: targetCatalogId!,
      };

      await saveCategoryMutation.mutateAsync({
        id: editingCategory?.id,
        data: payload,
      });

      toast(
        editingCategory
          ? "Category updated successfully"
          : "Category created successfully",
        { variant: "success" }
      );
      setShowModal(false);
      onRefresh();
    } catch (error) {
      const message: string =
        error instanceof Error ? error.message : "Failed to save category";
      toast(message, { variant: "error" });
    }
  };

  const handleDrop = async (draggedCatId: string, targetId: string | null): Promise<void> => {
    if (draggedCatId === targetId) return;

    try {
      await saveCategoryMutation.mutateAsync({
        id: draggedCatId,
        data: { parentId: targetId, catalogId: selectedCatalogId || undefined },
      });

      toast("Category moved successfully", { variant: "success" });
      onRefresh();
    } catch (error) {
      const message: string =
        error instanceof Error ? error.message : "Failed to move category";
      toast(message, { variant: "error" });
    }
  };

  const handleRootDrop = (e: React.DragEvent): void => {
    e.preventDefault();
    const catId: string = e.dataTransfer.getData("categoryId") || (draggedId ?? "");
    if (catId) {
      void handleDrop(catId, null);
    }
  };

  const selectedCatalog: Catalog | undefined = catalogs.find((c: Catalog): boolean => c.id === selectedCatalogId);
  const modalCatalog: Catalog | undefined = catalogs.find((c: Catalog): boolean => c.id === modalCatalogId);

  const findCategory = useCallback(
    (
      cats: ProductCategoryWithChildren[],
      id: string
    ): ProductCategoryWithChildren | null => {
      for (const cat of cats) {
        if (cat.id === id) return cat;
        const found: ProductCategoryWithChildren | null = findCategory(
          cat.children,
          id
        );
        if (found) return found;
      }
      return null;
    },
    []
  );

  const collectDescendantIds = useCallback((cat: ProductCategoryWithChildren): string[] => {
    const ids: string[] = [];
    for (const child of cat.children) {
      ids.push(child.id, ...collectDescendantIds(child));
    }
    return ids;
  }, []);

  const categoryOptions: { id: string; name: string; level: number }[] = useMemo((): { id: string; name: string; level: number }[] => {
    const flatten = (
      cats: ProductCategoryWithChildren[],
      level: number = 0
    ): { id: string; name: string; level: number }[] => {
      const items: { id: string; name: string; level: number }[] = [];
      for (const cat of cats) {
        items.push({ id: cat.id, name: cat.name, level });
        if (cat.children.length) {
          items.push(...flatten(cat.children, level + 1));
        }
      }
      return items;
    };
    return flatten(modalCategories);
  }, [modalCategories]);

  const excludedParentIds: Set<string> = useMemo((): Set<string> => {
    if (!editingCategory) return new Set<string>();
    if (modalCatalogId && editingCategory.catalogId !== modalCatalogId) {
      return new Set<string>();
    }
    const current: ProductCategoryWithChildren | null = findCategory(modalCategories, editingCategory.id);
    if (!current) return new Set<string>();
    return new Set([editingCategory.id, ...collectDescendantIds(current)]);
  }, [editingCategory, modalCatalogId, modalCategories, findCategory, collectDescendantIds]);

  const parentOptions: { id: string; name: string; level: number }[] = useMemo(
    (): { id: string; name: string; level: number }[] => categoryOptions.filter((opt: { id: string }): boolean => !excludedParentIds.has(opt.id)),
    [categoryOptions, excludedParentIds]
  );

  const loadModalCategories = useCallback(
    async (catalogId: string): Promise<void> => {
      setModalLoadingCategories(true);
      try {
        const res: Response = await fetch(
          `/api/products/categories/tree?catalogId=${catalogId}`
        );
        if (!res.ok) {
          const error: { error?: string } = (await res.json()) as { error?: string };
          throw new Error(error.error || "Failed to load categories.");
        }
        const data: ProductCategoryWithChildren[] = (await res.json()) as ProductCategoryWithChildren[];
        setModalCategories(data);
      } catch (error) {
        const message: string =
          error instanceof Error ? error.message : "Failed to load categories.";
        toast(message, { variant: "error" });
        setModalCategories([]);
      } finally {
        setModalLoadingCategories(false);
      }
    },
    [toast]
  );

  useEffect((): void => {
    if (!showModal || !modalCatalogId) return;
    if (modalCatalogId === selectedCatalogId) {
      setModalCategories(categories);
      return;
    }
    void loadModalCategories(modalCatalogId);
  }, [showModal, modalCatalogId, selectedCatalogId, categories, loadModalCategories]);

  useEffect((): void => {
    if (!showModal) return;
    if (!formData.parentId) return;
    const stillValid: boolean = parentOptions.some((opt: { id: string }): boolean => opt.id === formData.parentId);
    if (!stillValid) {
      setFormData((prev) => ({ ...prev, parentId: null }));
    }
  }, [showModal, parentOptions, formData.parentId]);

  return (
    <div className="space-y-5">
      {/* Catalog Selector */}
      <div className="rounded-md border border-border bg-card/60 p-4">
        <p className="text-sm font-semibold text-white mb-3">Select Catalog</p>
        <p className="text-xs text-gray-400 mb-3">
          Each catalog has its own category tree. Select a catalog to manage its categories.
        </p>
        <div className="w-full max-w-xs">
          <Select
            value={selectedCatalogId || ""}
            onValueChange={onCatalogChange}
          >
            <SelectTrigger suppressHydrationWarning>
              <SelectValue placeholder="Select a catalog..." />
            </SelectTrigger>
            <SelectContent>
              {catalogs.map((catalog: Catalog): React.JSX.Element => (
                <SelectItem key={catalog.id} value={catalog.id}>
                  {catalog.name}
                  {catalog.isDefault && " (Default)"}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Category Tree */}
      {selectedCatalogId && (
        <>
          <div className="flex justify-start">
            <Button
              onClick={(): void => handleOpenCreateModal(null)}
              className="bg-white text-gray-900 hover:bg-gray-200"
            >
              <Plus className="size-4 mr-2" />
              Add Category
            </Button>
          </div>

          <div className="rounded-md border border-border bg-card/60 p-4">
            <p className="text-sm font-semibold text-white mb-4">
              Category Tree for &quot;{selectedCatalog?.name}&quot;
            </p>

            {loading ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                Loading categories...
              </div>
            ) : categories.length === 0 ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                No categories yet for this catalog. Create your first category!
              </div>
            ) : (
              <div
                className="space-y-0.5 rounded-md border border-border bg-gray-900 p-2"
                onDragOver={(e: React.DragEvent): void => {
                  e.preventDefault();
                }}
                onDrop={handleRootDrop}
              >
                {/* Root drop zone */}
                <div
                  className="flex items-center gap-2 px-2 py-1.5 rounded text-sm text-gray-500 border border-dashed border mb-2"
                  onDragOver={(e: React.DragEvent): void => {
                    e.preventDefault();
                    (e.currentTarget as HTMLElement).classList.add("bg-emerald-600/20", "border-emerald-500");
                  }}
                  onDragLeave={(e: React.DragEvent): void => {
                    (e.currentTarget as HTMLElement).classList.remove("bg-emerald-600/20", "border-emerald-500");
                  }}
                  onDrop={(e: React.DragEvent): void => {
                    e.preventDefault();
                    (e.currentTarget as HTMLElement).classList.remove("bg-emerald-600/20", "border-emerald-500");
                    handleRootDrop(e);
                  }}
                >
                  <span>Drop here to move to root level</span>
                </div>

                {categories.map((category: ProductCategoryWithChildren): React.JSX.Element => (
                  <CategoryNode
                    key={category.id}
                    category={category}
                    level={0}
                    expandedIds={expandedIds}
                    onToggleExpand={handleToggleExpand}
                    onEdit={handleOpenEditModal}
                    onDelete={(cat: ProductCategoryWithChildren): void => void handleDelete(cat)}
                    onCreateChild={handleOpenCreateModal}
                    draggedId={draggedId}
                    onDragStart={setDraggedId}
                    onDragEnd={(): void => setDraggedId(null)}
                    onDrop={(e: string, targetId: string | null): void => void handleDrop(e, targetId)}
                    allCategories={categories}
                  />
                ))}
              </div>
            )}
          </div>
        </>
      )}

      {!selectedCatalogId && catalogs.length === 0 && (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          No catalogs found. Please create a catalog first in the Catalogs section.
        </div>
      )}

      {/* Create/Edit Modal */}
      {showModal && (
        <AppModal
          open={showModal}
          onOpenChange={(open: boolean): void => { if (!open) setShowModal(false); }}
          title={editingCategory ? "Edit Category" : "Create Category"}
        >
          <div className="w-full max-w-md rounded-lg bg-card p-6 shadow-lg">
            <div className="mb-4 flex items-center justify-between">
              <h2 className="text-xl font-semibold text-white">
                {editingCategory ? "Edit Category" : "Create Category"}
              </h2>
              <Button
                className="text-sm text-gray-400 hover:text-white"
                type="button"
                onClick={(): void => setShowModal(false)}
              >
                Close
              </Button>
            </div>

            <div className="space-y-4">
              <div>
                <Label className="text-xs text-gray-400">Name</Label>
                <Input
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  value={formData.name}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
                    setFormData((prev) => ({ ...prev, name: e.target.value }))
                  }
                  placeholder="Category name"
                />
              </div>

              <div>
                <Label className="text-xs text-gray-400">Description</Label>
                <Textarea
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  rows={3}
                  value={formData.description}
                  onChange={(e: React.ChangeEvent<HTMLTextAreaElement>): void =>
                    setFormData((prev) => ({
                      ...prev,
                      description: e.target.value,
                    }))
                  }
                  placeholder="Optional description"
                />
              </div>

              <div>
                <Label className="text-xs text-gray-400">Catalog</Label>
                <select
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  value={formData.catalogId}
                  onChange={(e: React.ChangeEvent<HTMLSelectElement>): void => {
                    const nextCatalogId: string = e.target.value;
                    setFormData((prev) => ({
                      ...prev,
                      catalogId: nextCatalogId,
                      parentId:
                        prev.catalogId !== nextCatalogId ? null : prev.parentId,
                    }));
                    setModalCatalogId(nextCatalogId);
                  }}
                >
                  {catalogs.map((catalog: Catalog): React.JSX.Element => (
                    <option key={catalog.id} value={catalog.id}>
                      {catalog.name}
                      {catalog.isDefault ? " (Default)" : ""}
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <Label className="text-xs text-gray-400">Parent Category</Label>
                <select
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  value={formData.parentId ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLSelectElement>): void =>
                    setFormData((prev) => ({
                      ...prev,
                      parentId: e.target.value ? e.target.value : null,
                    }))
                  }
                  disabled={modalLoadingCategories}
                >
                  <option value="">No parent (root)</option>
                  {parentOptions.map((option: { id: string; name: string; level: number }): React.JSX.Element => (
                    <option key={option.id} value={option.id}>
                      {"|-- ".repeat(option.level)}
                      {option.name}
                    </option>
                  ))}
                </select>
                {modalLoadingCategories && (
                  <p className="mt-1 text-xs text-gray-500">Loading categories...</p>
                )}
                {!modalLoadingCategories &&
                  modalCatalogId &&
                  parentOptions.length === 0 && (
                    <p className="mt-1 text-xs text-gray-500">
                      No categories available in{" "}
                      {modalCatalog?.name ?? "this catalog"}.
                    </p>
                  )}
              </div>

              <div>
                <Label className="text-xs text-gray-400">Color</Label>
                <div className="mt-2 flex items-center gap-3">
                  <Input
                    type="color"
                    className="h-10 w-20 cursor-pointer rounded border border-border bg-gray-900"
                    value={formData.color}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
                      setFormData((prev) => ({ ...prev, color: e.target.value }))
                    }
                  />
                  <Input
                    type="text"
                    className="flex-1 rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                    value={formData.color}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
                      setFormData((prev) => ({ ...prev, color: e.target.value }))
                    }
                    placeholder="#10b981"
                  />
                </div>
              </div>

              <div className="flex items-center justify-end gap-3 pt-4">
                <Button
                  className="rounded-md border border-border px-3 py-2 text-sm text-gray-300 hover:bg-muted/50"
                  type="button"
                  onClick={(): void => setShowModal(false)}
                >
                  Cancel
                </Button>
                <Button
                  className="rounded-md bg-white px-4 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200"
                  type="button"
                  onClick={(): void => { void handleSave(); }}
                  disabled={saveCategoryMutation.isPending}
                >
                  {saveCategoryMutation.isPending ? "Saving..." : "Save"}
                </Button>
              </div>
            </div>
          </div>
        </AppModal>
      )}
    </div>
  );
}

"use client";

import { useToast, Button, AppModal, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Input, Label } from "@/shared/ui";
import { useState } from "react";
import { Plus, Trash2 } from "lucide-react";

import type { Catalog, ProductTag } from "@/features/products/types";
import { useSaveTagMutation, useDeleteTagMutation } from "@/features/products/hooks/useProductSettingsQueries";

type TagsSettingsProps = {
  loading: boolean;
  tags: ProductTag[];
  catalogs: Catalog[];
  selectedCatalogId: string | null;
  onCatalogChange: (catalogId: string) => void;
  onRefresh: () => void;
};

export function TagsSettings({
  loading,
  tags,
  catalogs,
  selectedCatalogId,
  onCatalogChange,
  onRefresh,
}: TagsSettingsProps): React.JSX.Element {
  const { toast } = useToast();
  const [showModal, setShowModal] = useState(false);
  const [editingTag, setEditingTag] = useState<ProductTag | null>(null);
  const [formData, setFormData] = useState({
    name: "",
    color: "#38bdf8",
    catalogId: "",
  });

  const saveTagMutation = useSaveTagMutation();
  const deleteTagMutation = useDeleteTagMutation();

  const openCreateModal = (): void => {
    if (!selectedCatalogId) {
      toast("Please select a catalog first.", { variant: "error" });
      return;
    }
    setEditingTag(null);
    setFormData({
      name: "",
      color: "#38bdf8",
      catalogId: selectedCatalogId,
    });
    setShowModal(true);
  };

  const openEditModal = (tag: ProductTag): void => {
    setEditingTag(tag);
    setFormData({
      name: tag.name,
      color: tag.color ?? "#38bdf8",
      catalogId: tag.catalogId,
    });
    setShowModal(true);
  };

  const handleSave = async (): Promise<void> => {
    if (!formData.name.trim()) {
      toast("Tag name is required.", { variant: "error" });
      return;
    }
    if (!formData.catalogId) {
      toast("Catalog is required.", { variant: "error" });
      return;
    }

    try {
      const payload = {
        name: formData.name.trim(),
        color: formData.color.trim() || null,
        catalogId: formData.catalogId,
      };

      await saveTagMutation.mutateAsync({
        id: editingTag?.id,
        data: payload,
      });

      toast(editingTag ? "Tag updated." : "Tag created.", {
        variant: "success",
      });
      setShowModal(false);
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to save tag.";
      toast(message, { variant: "error" });
    }
  };

  const handleDelete = async (tag: ProductTag): Promise<void> => {
    const confirmed = window.confirm(`Delete tag "${tag.name}"?`);
    if (!confirmed) return;
    try {
      await deleteTagMutation.mutateAsync({ id: tag.id, catalogId: selectedCatalogId });
      toast("Tag deleted.", { variant: "success" });
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to delete tag.";
      toast(message, { variant: "error" });
    }
  };

  const selectedCatalog = catalogs.find((catalog: Catalog) => catalog.id === selectedCatalogId);

  return (
    <div className="space-y-5">
      <div className="rounded-md border border-border bg-card/60 p-4">
        <p className="text-sm font-semibold text-white mb-3">Select Catalog</p>
        <p className="text-xs text-gray-400 mb-3">
          Tags are managed per catalog.
        </p>
        <div className="w-full max-w-xs">
          <Select
            value={selectedCatalogId || ""}
            onValueChange={onCatalogChange}
          >
            <SelectTrigger suppressHydrationWarning>
              <SelectValue placeholder="Select a catalog..." />
            </SelectTrigger>
            <SelectContent>
              {catalogs.map((catalog: Catalog) => (
                <SelectItem key={catalog.id} value={catalog.id}>
                  {catalog.name}
                  {catalog.isDefault ? " (Default)" : ""}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {selectedCatalogId && (
        <>
          <div className="flex justify-start">
            <Button
              onClick={openCreateModal}
              className="bg-white text-gray-900 hover:bg-gray-200"
            >
              <Plus className="size-4 mr-2" />
              Add Tag
            </Button>
          </div>

          <div className="rounded-md border border-border bg-card/60 p-4">
            <p className="text-sm font-semibold text-white mb-4">
              Tags for &quot;{selectedCatalog?.name}&quot;
            </p>

            {loading ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                Loading tags...
              </div>
            ) : tags.length === 0 ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                No tags yet for this catalog. Create your first tag!
              </div>
            ) : (
              <div className="space-y-2">
                {tags.map((tag: ProductTag) => (
                  <div
                    key={tag.id}
                    className="flex items-center justify-between gap-3 rounded-md border border-border bg-gray-900 px-3 py-2"
                  >
                    <div className="flex items-center gap-3 min-w-0">
                      <span
                        className="size-3 rounded-full border border"
                        style={{ backgroundColor: tag.color || "#38bdf8" }}
                      />
                      <span className="text-sm text-gray-100 truncate">
                        {tag.name}
                      </span>
                    </div>
                    <div className="flex items-center gap-2">
                      <Button
                        type="button"
                        onClick={(): void => openEditModal(tag)}
                        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-100 hover:bg-gray-700"
                      >
                        Edit
                      </Button>
                      <Button
                        type="button"
                        onClick={(): void => { void handleDelete(tag); }}
                        className="rounded bg-red-600/80 px-2 py-1 text-xs text-white hover:bg-red-600"
                        title="Delete tag"
                      >
                        <Trash2 className="size-3" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}

      {!selectedCatalogId && catalogs.length === 0 && (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          No catalogs found. Please create a catalog first in the Catalogs section.
        </div>
      )}

      {showModal && (
        <AppModal
          open={showModal}
          onOpenChange={(open: boolean): void => { if (!open) setShowModal(false); }}
          title={editingTag ? "Edit Tag" : "Create Tag"}
        >
          <div className="w-full max-w-md rounded-lg bg-card p-6 shadow-lg">
            <div className="mb-4 flex items-center justify-between">
              <h2 className="text-xl font-semibold text-white">
                {editingTag ? "Edit Tag" : "Create Tag"}
              </h2>
              <Button
                className="text-sm text-gray-400 hover:text-white"
                type="button"
                onClick={(): void => setShowModal(false)}
              >
                Close
              </Button>
            </div>

            <div className="space-y-4">
              <div>
                <Label className="text-xs text-gray-400">Name</Label>
                <Input
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  value={formData.name}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
                    setFormData((prev) => ({ ...prev, name: e.target.value }))
                  }
                  placeholder="Tag name"
                />
              </div>

              <div>
                <Label className="text-xs text-gray-400">Catalog</Label>
                <select
                  className="mt-2 w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                  value={formData.catalogId}
                  onChange={(e: React.ChangeEvent<HTMLSelectElement>): void =>
                    setFormData((prev) => ({
                      ...prev,
                      catalogId: e.target.value,
                    }))
                  }
                >
                  {catalogs.map((catalog: Catalog) => (
                    <option key={catalog.id} value={catalog.id}>
                      {catalog.name}
                      {catalog.isDefault ? " (Default)" : ""}
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <Label className="text-xs text-gray-400">Color</Label>
                <div className="mt-2 flex items-center gap-3">
                  <Input
                    type="color"
                    className="h-10 w-20 cursor-pointer rounded border border-border bg-gray-900"
                    value={formData.color}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
                      setFormData((prev) => ({ ...prev, color: e.target.value }))
                    }
                  />
                  <Input
                    type="text"
                    className="flex-1 rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                    value={formData.color}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
                      setFormData((prev) => ({ ...prev, color: e.target.value }))
                    }
                    placeholder="#38bdf8"
                  />
                </div>
              </div>

              <div className="flex items-center justify-end gap-3 pt-4">
                <Button
                  className="rounded-md border border-border px-3 py-2 text-sm text-gray-300 hover:bg-muted/50"
                  type="button"
                  onClick={(): void => setShowModal(false)}
                >
                  Cancel
                </Button>
                <Button
                  className="rounded-md bg-white px-4 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200"
                  type="button"
                  onClick={(): void => { void handleSave(); }}
                  disabled={saveTagMutation.isPending}
                >
                  {saveTagMutation.isPending ? "Saving..." : "Save"}
                </Button>
              </div>
            </div>
          </div>
        </AppModal>
      )}
    </div>
  );
}

"use client";

import { useToast } from "@/shared/ui";
import type { Language } from "@/shared/types/internationalization";
import { zodResolver } from "@hookform/resolvers/zod";
import { useRouter } from "next/navigation";
import {
  createContext,
  useContext,
  useState,
  BaseSyntheticEvent,
  useRef,
  useEffect,
} from "react";
import { useQueryClient } from "@tanstack/react-query";
import {
  UseFormRegister,
  UseFormSetValue,
  UseFormGetValues,
  FieldErrors,
  FormProvider,
  useForm,
  Resolver,
} from "react-hook-form";

import type {
  CatalogRecord,
  ProductWithImages,
  PriceGroupWithDetails,
  ProductFormData,
  ProductDraft,
} from "@/features/products/types";
import type { ImageFileSelection } from "@/shared/types/files";
import type { ProductCategory, ProductTag, ProductParameter, ProductParameterValue } from "@/features/products/types";
import {
  ProductImageSlot,
} from "@/features/products/types/products-ui";
import {
  productCreateSchema,
  productUpdateSchema,
} from "@/features/products/validations";

import { useProductImages } from "@/features/products/hooks/useProductImages";
import { useProductMetadata } from "@/features/products/hooks/useProductMetadata";
import { delay } from "@/shared/utils";
import { useCreateProductMutation, useUpdateProductMutation } from "@/features/products/hooks/useProductData";

interface ProductFormContextType {
  register: UseFormRegister<ProductFormData>;
  handleSubmit: (e?: BaseSyntheticEvent) => Promise<void>;
  errors: FieldErrors<ProductFormData>;
  setValue: UseFormSetValue<ProductFormData>;
  getValues: UseFormGetValues<ProductFormData>;
  imageSlots: (ProductImageSlot | null)[];
  imageLinks: string[];
  uploading: boolean;
  uploadError: string | null;
  uploadSuccess: boolean;
  showFileManager: boolean;
  setShowFileManager: (show: boolean) => void;
  handleSlotImageChange: (file: File | null, index: number) => void;
  handleSlotFileSelect: (file: ImageFileSelection | null, index: number) => void;
  handleSlotDisconnectImage: (index: number) => Promise<void>;
  handleMultiImageChange: (files: File[]) => void;
  handleMultiFileSelect: (files: ImageFileSelection[]) => void;
  swapImageSlots: (fromIndex: number, toIndex: number) => void;
  setImageLinkAt: (index: number, value: string) => void;
  setImagesReordering: (reordering: boolean) => void;
  catalogs: CatalogRecord[];
  catalogsLoading: boolean;
  catalogsError: string | null;
  selectedCatalogIds: string[];
  toggleCatalog: (catalogId: string) => void;
  categories: ProductCategory[];
  categoriesLoading: boolean;
  selectedCategoryIds: string[];
  toggleCategory: (categoryId: string) => void;
  tags: ProductTag[];
  tagsLoading: boolean;
  selectedTagIds: string[];
  toggleTag: (tagId: string) => void;
  parameters: ProductParameter[];
  parametersLoading: boolean;
  parameterValues: ProductParameterValue[];
  addParameterValue: () => void;
  updateParameterId: (index: number, parameterId: string) => void;
  updateParameterValue: (index: number, value: string) => void;
  removeParameterValue: (index: number) => void;
  filteredLanguages: Language[];
  filteredPriceGroups: PriceGroupWithDetails[];
  generationError: string | null;
  setGenerationError: (error: string | null) => void;
  product?: ProductWithImages | undefined;
}

export const ProductFormContext = createContext<ProductFormContextType | null>(
  null
);

export const useProductFormContext = (): ProductFormContextType => {
  const context = useContext(ProductFormContext);
  if (!context) {
    throw new Error(
      "useProductFormContext must be used within a ProductFormProvider"
    );
  }
  return context;
};

// This context provides a centralized place for managing the state and logic of the product form.
// It handles form data, image uploads, and communication with the API.
export function ProductFormProvider({
  children,
  product,
  draft,
  onSuccess,
  onEditSave,
  requireSku,
  initialSku,
  initialCatalogId,
}: {
  children: React.ReactNode;
  product?: ProductWithImages | undefined;
  draft?: ProductDraft | null | undefined;
  onSuccess?: (() => void) | undefined;
  onEditSave?: ((saved: ProductWithImages) => void) | undefined;
  requireSku?: boolean | undefined;
  initialSku?: string | undefined;
  initialCatalogId?: string | undefined;
}): React.ReactNode {
  const formSchema = product || requireSku ? productUpdateSchema : productCreateSchema;
  const methods = useForm<ProductFormData>({
    resolver: zodResolver(formSchema) as Resolver<ProductFormData>,
    defaultValues: {
      name_en: product?.name_en || draft?.name_en || "",
      name_pl: product?.name_pl || draft?.name_pl || "",
      name_de: product?.name_de || draft?.name_de || "",
      price: product?.price ?? draft?.price ?? 0,
      sku: product?.sku || initialSku || draft?.sku || "",
      defaultPriceGroupId:
        product?.defaultPriceGroupId ?? draft?.defaultPriceGroupId ?? undefined,
      baseProductId: product?.baseProductId ?? draft?.baseProductId ?? undefined,
      ean: product?.ean || draft?.ean || "",
      gtin: product?.gtin || draft?.gtin || "",
      asin: product?.asin || draft?.asin || "",
      description_en: product?.description_en || draft?.description_en || "",
      description_pl: product?.description_pl || draft?.description_pl || "",
      description_de: product?.description_de || draft?.description_de || "",
      supplierName: product?.supplierName || draft?.supplierName || "",
      supplierLink: product?.supplierLink || draft?.supplierLink || "",
      priceComment: product?.priceComment || draft?.priceComment || "",
      stock: product?.stock ?? draft?.stock ?? 0,
      sizeLength: product?.sizeLength ?? draft?.sizeLength ?? 0,
      sizeWidth: product?.sizeWidth ?? draft?.sizeWidth ?? 0,
      weight: product?.weight ?? draft?.weight ?? 0,
      length: product?.length ?? draft?.length ?? 0,
    },
  });
  const {
    register,
    formState: { errors },
    setValue,
    getValues,
  } = methods;
  const router = useRouter();
  const queryClient = useQueryClient();
  const [uploadError, setUploadError] = useState<string | null>(null);
  const [uploadSuccess, setUploadSuccess] = useState(false);
  const successTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [generationError, setGenerationError] = useState<string | null>(null);
  const { toast } = useToast();

  const createMutation = useCreateProductMutation();
  const updateMutation = useUpdateProductMutation();

  const {
    imageSlots,
    imageLinks,
    showFileManager,
    setShowFileManager,
    handleSlotImageChange,
    handleSlotFileSelect,
    handleSlotDisconnectImage,
    handleMultiImageChange,
    handleMultiFileSelect,
    swapImageSlots,
    setImageLinkAt,
    refreshFromProduct: refreshImages,
    setImagesReordering,
  } = useProductImages(product, draft?.imageLinks);

  const {
    catalogs,
    catalogsLoading,
    catalogsError,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading,
    selectedCategoryIds,
    toggleCategory,
    tags,
    tagsLoading,
    selectedTagIds,
    toggleTag,
    parameters,
    parametersLoading,
    filteredLanguages,
    filteredPriceGroups,
  } = useProductMetadata({
    product,
    initialCatalogId,
    initialCatalogIds: draft?.catalogIds,
    initialCategoryIds: draft?.categoryIds,
    initialTagIds: draft?.tagIds,
    setValue,
    getValues,
  });

  const normalizeParameterValues = (
    input?: ProductParameterValue[] | null
  ): ProductParameterValue[] => {
    if (!Array.isArray(input)) return [];
    return input.map((entry: ProductParameterValue) => ({
      parameterId: typeof entry?.parameterId === "string" ? entry.parameterId : "",
      value: typeof entry?.value === "string" ? entry.value : "",
    }));
  };

  const [parameterValues, setParameterValues] = useState<ProductParameterValue[]>(
    () => normalizeParameterValues(product?.parameters ?? draft?.parameters ?? [])
  );

  useEffect(() => {
    setParameterValues(normalizeParameterValues(product?.parameters ?? draft?.parameters ?? []));
  }, [product?.id, draft?.id, product?.parameters, draft?.parameters]);

  useEffect((): (() => void) => {
    return (): void => {
      if (successTimerRef.current) {
        clearTimeout(successTimerRef.current);
      }
    };
  }, []);

  const onSubmit = async (data: ProductFormData): Promise<void> => {
    const skuValue = typeof data.sku === "string" ? data.sku.trim() : "";
    const hasTempImages = imageSlots.some((slot: ProductImageSlot | null): boolean => {
      if (!slot) return false;
      if (slot.type === "file") return true;
      return slot.previewUrl.startsWith("/uploads/products/temp/");
    });

    if (!skuValue && hasTempImages) {
      const shouldContinue = window.confirm(
        "This product has images without an SKU. They will stay in the temporary folder until you set an SKU. Continue?"
      );
      if (!shouldContinue) {
        return;
      }
    }

    setUploadError(null);
    setUploadSuccess(false);

    const formData = new FormData();
    Object.entries(data).forEach(([key, value]: [string, unknown]): void => {
      if (value !== null && value !== undefined) {
        if (typeof value === "object") {
          formData.append(key, JSON.stringify(value));
        } else if (typeof value === "string") {
          formData.append(key, value);
        } else {
          formData.append(key, String(value as number | boolean));
        }
      }
    });
    const normalizedLinks = imageLinks.map((link: string): string => link.trim());
    formData.append("imageLinks", JSON.stringify(normalizedLinks));

    // Process image slots
    imageSlots.forEach((slot: ProductImageSlot | null): void => {
      if (slot?.type === 'file') {
        formData.append("images", slot.data); // Append actual File object
      } else if (slot?.type === 'existing') {
        formData.append("imageFileIds", slot.data.id); // Append existing ImageFile ID
      }
    });
    selectedCatalogIds.forEach((catalogId: string): void => {
      formData.append("catalogIds", catalogId);
    });
    selectedCategoryIds.forEach((categoryId: string): void => {
      formData.append("categoryIds", categoryId);
    });
    selectedTagIds.forEach((tagId: string): void => {
      formData.append("tagIds", tagId);
    });
    const normalizedParameters = parameterValues
      .map((entry: ProductParameterValue): { parameterId: string | undefined; value: string } => ({
        parameterId: entry.parameterId?.trim(),
        value: typeof entry.value === "string" ? entry.value.trim() : "",
      }))
      .filter((entry: { parameterId: string | undefined; value: string }): boolean => !!entry.parameterId);
    formData.append("parameters", JSON.stringify(normalizedParameters));

    try {
      let savedProduct: ProductWithImages;

      if (product) {
        // Update mode - we can't easily use FormData with our current update mutation because it expects JSON
        // Actually, the API route handles both.
        // Let's check the API route.

        // Wait, updateProduct in api/products.ts uses fetch with body: JSON.stringify(data)
        // If we want to support images, we might need a separate endpoint or multipart support.
        // The context code above uses fetch(url, { method: "PUT", body: formData })

        const response = await fetch(`/api/products/${product.id}`, {
          method: "PUT",
          body: formData,
        });

        if (!response.ok) {
          const errorData = await response.json().catch(() => ({}));
          throw new Error(errorData.error || "Failed to update product");
        }
        savedProduct = await response.json();
      } else {
        savedProduct = (await createMutation.mutateAsync(formData)) as ProductWithImages;
      }

      toast(product ? "Product updated." : "Product created.", {
        variant: "success",
      });

      // Small delay to ensure DB consistency before refetch
      await delay(500);

      // Invalidate both products list and count queries
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);

      if (!product) {
        onSuccess?.();
      } else {
        refreshImages(savedProduct);
        setUploadSuccess(true);
        if (successTimerRef.current) {
          clearTimeout(successTimerRef.current);
        }
        successTimerRef.current = setTimeout(() => {
          setUploadSuccess(false);
        }, 3000);
        onEditSave?.(savedProduct);
        router.refresh();
      }
    } catch (error: unknown) {
      if (error instanceof Error) {
        setUploadError(error.message);
      } else {
        setUploadError("An unknown error occurred");
      }
    }
  };

  return (
    <FormProvider {...methods}>
      <ProductFormContext.Provider
        value={{
          register,
          handleSubmit: methods.handleSubmit(onSubmit),
          errors,
          setValue,
          getValues,
          imageSlots,
          imageLinks,
          uploading: createMutation.isPending || updateMutation.isPending,
          uploadError,
          uploadSuccess,
          showFileManager,
          setShowFileManager,
          handleSlotImageChange,
          handleSlotFileSelect,
          handleSlotDisconnectImage,
          handleMultiImageChange,
          handleMultiFileSelect,
          swapImageSlots,
          setImageLinkAt,
          setImagesReordering,
          catalogs,
          catalogsLoading,
          catalogsError,
          selectedCatalogIds,
          toggleCatalog,
          categories,
          categoriesLoading,
          selectedCategoryIds,
          toggleCategory,
          tags,
          tagsLoading,
          selectedTagIds,
          toggleTag,
          parameters,
          parametersLoading,
          parameterValues,
          addParameterValue: (): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => [...prev, { parameterId: "", value: "" }]),
          updateParameterId: (index: number, parameterId: string): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
              const next = [...prev];
              if (!next[index]) return prev;
              next[index] = { ...next[index], parameterId };
              return next;
            }),
          updateParameterValue: (index: number, value: string): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
              const next = [...prev];
              if (!next[index]) return prev;
              next[index] = { ...next[index], value };
              return next;
            }),
          removeParameterValue: (index: number): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => prev.filter((_: ProductParameterValue, i: number): boolean => i !== index)),
          filteredLanguages,
          filteredPriceGroups,
          generationError,
          setGenerationError,
          product,
        }}
      >
        {children}
      </ProductFormContext.Provider>
    </FormProvider>
  );
}

