"use client";

import { useQuery, useMutation, useQueryClient, type UseMutationResult, type UseQueryResult } from "@tanstack/react-query";
import { useState, useMemo, useEffect, useCallback } from "react";
import { 
  getProducts, 
  countProducts, 
  createProduct, 
  updateProduct, 
  deleteProduct 
} from "@/features/products/api";
import type { 
  ProductWithImages, 
} from "@/features/products/types";
import type { DeleteResponse } from "@/shared/types/api";

// --- Queries ---

export interface UseProductsFilters {
  search?: string | undefined;
  sku?: string | undefined;
  minPrice?: number | undefined;
  maxPrice?: number | undefined;
  startDate?: string | undefined;
  endDate?: string | undefined;
  page?: number | undefined;
  pageSize?: number | undefined;
  catalogId?: string | undefined;
  searchLanguage?: string | undefined;
}

export function useProducts(
  filters: UseProductsFilters,
  options: { enabled?: boolean } = {}
): UseQueryResult<ProductWithImages[], Error> {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products", filters],
    queryFn: () => getProducts(filters),
    enabled,
  });
}

export function useProductsCount(
  filters: UseProductsFilters,
  options: { enabled?: boolean } = {}
): UseQueryResult<number, Error> {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products-count", filters],
    queryFn: () => countProducts(filters),
    enabled,
  });
}

// --- Mutations ---

export function useCreateProductMutation(): UseMutationResult<unknown, Error, FormData, unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (formData: FormData) => createProduct(formData),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["products"] });
      queryClient.invalidateQueries({ queryKey: ["products-count"] });
    },
  });
}

export function useUpdateProductMutation(): UseMutationResult<ProductWithImages, Error, { id: string; data: Partial<ProductWithImages> | FormData }, unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, data }) => {
      if (data instanceof FormData) {
        const response = await fetch(`/api/products/${id}`, {
          method: "PUT",
          body: data,
        });
        if (!response.ok) throw new Error("Failed to update product");
        return response.json();
      } else {
        return updateProduct(id, data);
      }
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ["products"] });
      queryClient.invalidateQueries({ queryKey: ["products", data.id] });
    },
  });
}

export function useDeleteProductMutation(): UseMutationResult<DeleteResponse, Error, string, unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (id: string) => deleteProduct(id) as Promise<DeleteResponse>,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["products"] });
      queryClient.invalidateQueries({ queryKey: ["products-count"] });
    },
  });
}

export function useBulkDeleteProductsMutation(): UseMutationResult<{ success: boolean }, Error, string[], unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (ids: string[]) => {
      const responses = await Promise.all(
        ids.map(id => deleteProduct(id))
      );
      if (responses.some(r => !r.success)) throw new Error("Failed to delete some products");
      return { success: true };
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["products"] });
      queryClient.invalidateQueries({ queryKey: ["products-count"] });
    },
  });
}

// --- Composite Hook ---

export interface UseProductDataProps {
  refreshTrigger?: number;
  initialCatalogFilter?: string | null;
  initialPageSize?: number | null;
  preferencesLoaded: boolean;
  currencyCode?: string | null;
  priceGroups?: any[];
  searchLanguage?: string | null;
}

export interface ProductDataHookResult {
  data: ProductWithImages[];
  totalPages: number;
  page: number;
  setPage: (p: number) => void;
  pageSize: number;
  setPageSize: (size: number) => void;
  search: string;
  setSearch: (s: string) => void;
  sku: string;
  setSku: (s: string) => void;
  minPrice: number | undefined;
  setMinPrice: (p: number | undefined) => void;
  maxPrice: number | undefined;
  setMaxPrice: (p: number | undefined) => void;
  startDate: string | undefined;
  setStartDate: (s: string | undefined) => void;
  endDate: string | undefined;
  setEndDate: (s: string | undefined) => void;
  catalogFilter: string;
  setCatalogFilter: (f: string) => void;
  loadError: Error | null;
  isLoading: boolean;
  isFetching: boolean;
  refresh: () => void;
}

export function useProductData({
  refreshTrigger,
  initialCatalogFilter,
  initialPageSize,
  preferencesLoaded,
  searchLanguage,
}: UseProductDataProps): ProductDataHookResult {
  const queryClient = useQueryClient();

  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(initialPageSize || 20);
  const [search, setSearch] = useState("");
  const [sku, setSku] = useState("");
  const [minPrice, setMinPrice] = useState<number | undefined>(undefined);
  const [maxPrice, setMaxPrice] = useState<number | undefined>(undefined);
  const [startDate, setStartDate] = useState<string | undefined>(undefined);
  const [endDate, setEndDate] = useState<string | undefined>(undefined);
  const [catalogFilter, setCatalogFilter] = useState(initialCatalogFilter || "all");

  useEffect(() => {
    if (preferencesLoaded && initialCatalogFilter) {
      setCatalogFilter(initialCatalogFilter);
    }
  }, [preferencesLoaded, initialCatalogFilter]);

  useEffect(() => {
    if (preferencesLoaded && initialPageSize) {
      setPageSize(initialPageSize);
    }
  }, [preferencesLoaded, initialPageSize]);

  const filters: UseProductsFilters = useMemo(() => ({
    search: search || undefined,
    sku: sku || undefined,
    minPrice,
    maxPrice,
    startDate: startDate || undefined,
    endDate: endDate || undefined,
    page,
    pageSize,
    catalogId: catalogFilter === "all" ? undefined : catalogFilter,
    searchLanguage: searchLanguage || undefined,
  }), [search, sku, minPrice, maxPrice, startDate, endDate, page, pageSize, catalogFilter, searchLanguage]);

  const productsQuery = useProducts(filters, { enabled: preferencesLoaded });
  const countQuery = useProductsCount(filters, { enabled: preferencesLoaded });

  const totalPages = useMemo(() => {
    const total = countQuery.data || 0;
    return Math.ceil(total / pageSize);
  }, [countQuery.data, pageSize]);

  const refresh = useCallback(() => {
    void queryClient.invalidateQueries({ queryKey: ["products"] });
    void queryClient.invalidateQueries({ queryKey: ["products-count"] });
  }, [queryClient]);

  // Invalidate when refreshTrigger changes
  useEffect(() => {
    if (refreshTrigger) {
      refresh();
    }
  }, [refreshTrigger, refresh]);

  return {
    data: productsQuery.data || [],
    totalPages,
    page,
    setPage,
    pageSize,
    setPageSize,
    search,
    setSearch,
    sku,
    setSku,
    minPrice,
    setMinPrice,
    maxPrice,
    setMaxPrice,
    startDate,
    setStartDate,
    endDate,
    setEndDate,
    catalogFilter,
    setCatalogFilter,
    loadError: (productsQuery.error || countQuery.error) as Error | null,
    isLoading: productsQuery.isLoading || countQuery.isLoading,
    isFetching: productsQuery.isFetching || countQuery.isFetching,
    refresh,
  };
}

"use client";

import { useState, useMemo, useCallback, useEffect } from "react";
import { useProductsWithCount } from "@/features/products/hooks/useProductsQuery";
import type { ProductWithImages } from "@/features/products/types";

interface UseProductDataWithQueryProps {
  initialCatalogFilter?: string;
  initialPageSize?: number;
  preferencesLoaded?: boolean;
}

interface UseProductDataWithQueryReturn {
  data: ProductWithImages[];
  total: number;
  totalPages: number;
  page: number;
  setPage: (page: number) => void;
  pageSize: number;
  setPageSize: (size: number) => void;
  search: string;
  setSearch: (value: string) => void;
  sku: string;
  setSku: (value: string) => void;
  minPrice: number | undefined;
  setMinPrice: (value: number | undefined) => void;
  maxPrice: number | undefined;
  setMaxPrice: (value: number | undefined) => void;
  startDate: string;
  setStartDate: (value: string) => void;
  endDate: string;
  setEndDate: (value: string) => void;
  catalogFilter: string;
  setCatalogFilter: (filter: string) => void;
  isLoading: boolean;
  isFetching: boolean;
  error: string | null;
  refetch: () => Promise<void>;
  resetFilters: () => void;
}

export function useProductDataWithQuery({
  initialCatalogFilter = "all",
  initialPageSize = 24,
  preferencesLoaded = true,
}: UseProductDataWithQueryProps = {}): UseProductDataWithQueryReturn {
  // Filter state
  const [search, setSearch] = useState<string>("");
  const [debouncedSearch, setDebouncedSearch] = useState<string>("");
  const [sku, setSku] = useState<string>("");
  const [debouncedSku, setDebouncedSku] = useState<string>("");
  const [minPrice, setMinPrice] = useState<number | undefined>(undefined);
  const [maxPrice, setMaxPrice] = useState<number | undefined>(undefined);
  const [startDate, setStartDate] = useState<string>("");
  const [endDate, setEndDate] = useState<string>("");
  const [catalogFilter, setCatalogFilter] = useState(initialCatalogFilter);

  // Pagination state
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(initialPageSize);

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(search);
      setPage(1);
    }, 300);
    return (): void => clearTimeout(timer);
  }, [search]);

  // Debounce SKU
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSku(sku);
      setPage(1);
    }, 300);
    return (): void => clearTimeout(timer);
  }, [sku]);

  const filters = useMemo(
    () => ({
      search: debouncedSearch,
      sku: debouncedSku,
      minPrice,
      maxPrice,
      startDate,
      endDate,
      page,
      pageSize,
      catalogId: catalogFilter === "all" ? undefined : catalogFilter,
    }),
    [
      debouncedSearch,
      debouncedSku,
      minPrice,
      maxPrice,
      startDate,
      endDate,
      page,
      pageSize,
      catalogFilter,
    ],
  );

  const { products, total, isLoading, isFetching, error, refetch } =
    useProductsWithCount(filters, {
      enabled: preferencesLoaded,
    });

  const totalPages = useMemo((): number => {
    return Math.max(1, Math.ceil(total / pageSize));
  }, [total, pageSize]);

  const resetFilters = useCallback((): void => {
    setSearch("");
    setDebouncedSearch("");
    setSku("");
    setDebouncedSku("");
    setMinPrice(undefined);
    setMaxPrice(undefined);
    setStartDate("");
    setEndDate("");
    setPage(1);
  }, []);

  return {
    data: products,
    total,
    totalPages,
    page,
    setPage,
    pageSize,
    setPageSize,
    search,
    setSearch,
    sku,
    setSku,
    minPrice,
    setMinPrice,
    maxPrice,
    setMaxPrice,
    startDate,
    setStartDate,
    endDate,
    setEndDate,
    catalogFilter,
    setCatalogFilter,
    isLoading,
    isFetching,
    error: error
      ? error instanceof Error
        ? error.message
        : "Failed to load products"
      : null,
    refetch,
    resetFilters,
  };
}

import { useState, useCallback, useRef, useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import type { ProductWithImages } from "@/features/products/types";
import type { ImageFileSelection } from "@/shared/types/files";
import type { ProductImageSlot } from "@/features/products/types/products-ui";

const TOTAL_IMAGE_SLOTS = 15;

const normalizeImageLinks = (links?: string[] | null): string[] => {
  const next: string[] = new Array<string>(TOTAL_IMAGE_SLOTS).fill("");
  if (Array.isArray(links)) {
    links.slice(0, TOTAL_IMAGE_SLOTS).forEach((link, index) => {
      next[index] = typeof link === "string" ? link : "";
    });
  }
  return next;
};

const buildImageSlotsFromProduct = (
  product?: ProductWithImages,
): (ProductImageSlot | null)[] => {
  const slots: (ProductImageSlot | null)[] = Array.from(
    { length: TOTAL_IMAGE_SLOTS },
    () => null,
  );
  if (!product?.images?.length) return slots;
  product.images.slice(0, TOTAL_IMAGE_SLOTS).forEach((pImg, index) => {
    if (pImg.imageFile) {
      slots[index] = {
        type: "existing",
        data: pImg.imageFile as ImageFileSelection,
        previewUrl: pImg.imageFile.filepath,
        slotId: pImg.imageFile.id,
      };
    }
  });
  return slots;
};

const createSlotId = () =>
  typeof crypto !== "undefined" && "randomUUID" in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(16).slice(2)}`;

export function useProductImages(
  product?: ProductWithImages,
  initialImageLinks?: string[] | null,
) {
  const [imageSlots, setImageSlots] = useState<(ProductImageSlot | null)[]>(
    () => buildImageSlotsFromProduct(product),
  );
  const [imageLinks, setImageLinks] = useState<string[]>(() =>
    normalizeImageLinks(product?.imageLinks ?? initialImageLinks),
  );
  const [showFileManager, setShowFileManager] = useState(false);
  const objectUrlsRef = useRef<string[]>([]);
  const isReorderingRef = useRef(false);
  const pendingRefreshRef = useRef<ProductWithImages | null>(null);

  const queryClient = useQueryClient();
  const disconnectImageMutation = useMutation({
    mutationFn: async ({ productId, imageFileId }: { productId: string; imageFileId: string }) => {
      const res = await fetch(`/api/products/${productId}/images/${imageFileId}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to disconnect image");
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: ["products"] });
    }
  });

  // Effect to clean up object URLs when component unmounts or imageSlots change
  useEffect(() => {
    const currentObjectUrls = imageSlots
      .map((slot) => (slot?.type === "file" ? slot.previewUrl : null))
      .filter(Boolean) as string[];

    // Revoke old object URLs that are no longer in use
    const oldObjectUrls = objectUrlsRef.current.filter(
      (url) => !currentObjectUrls.includes(url),
    );
    oldObjectUrls.forEach((url) => URL.revokeObjectURL(url));

    // Update ref with current object URLs
    objectUrlsRef.current = currentObjectUrls;

    return () => {
      // Clean up all object URLs on unmount
      objectUrlsRef.current.forEach((url) => URL.revokeObjectURL(url));
      objectUrlsRef.current = [];
    };
  }, [imageSlots]);

  const handleSlotImageChange = useCallback(
    (file: File | null, index: number) => {
      setImageSlots((prevSlots) => {
        const newSlots = [...prevSlots];
        if (file) {
          // Revoke existing object URL if replacing an image
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = {
            type: "file",
            data: file,
            previewUrl: URL.createObjectURL(file),
            slotId: createSlotId(),
          };
        } else {
          // Revoke object URL if clearing the slot
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = null;
        }
        return newSlots;
      });
    },
    [],
  );

  const handleSlotFileSelect = useCallback(
    (file: ImageFileSelection | null, index: number) => {
      setImageSlots((prevSlots) => {
        const newSlots = [...prevSlots];
        if (file) {
          // Revoke object URL if replacing a file upload with an existing file
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = {
            type: "existing",
            data: file,
            previewUrl: file.filepath,
            slotId: file.id,
          };
        } else {
          // Revoke object URL if clearing the slot
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = null;
        }
        return newSlots;
      });
      setShowFileManager(false);
    },
    [],
  );

  const handleSlotDisconnectImage = useCallback(
    async (index: number) => {
      const slotToClear = imageSlots[index];
      if (!slotToClear) return;

      setImageSlots((prevSlots) => {
        const newSlots = [...prevSlots];
        newSlots[index] = null;
        return newSlots;
      });

      if (slotToClear.type === "existing" && product?.id) {
        try {
          await disconnectImageMutation.mutateAsync({
            productId: product.id,
            imageFileId: slotToClear.data.id,
          });
        } catch (error) {
          console.error("Failed to disconnect image from product:", error);
        }
      } else if (slotToClear.type === "file") {
        URL.revokeObjectURL(slotToClear.previewUrl);
      }
    },
    [imageSlots, product, disconnectImageMutation],
  );

  const setImageLinkAt = useCallback((index: number, value: string) => {
    setImageLinks((prev) => {
      const next = [...prev];
      if (index < 0 || index >= next.length) return prev;
      next[index] = value;
      return next;
    });
  }, []);

  const handleMultiImageChange = useCallback((files: File[]) => {
    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      let fileIndex = 0;
      for (let i = 0; i < TOTAL_IMAGE_SLOTS && fileIndex < files.length; i++) {
        if (newSlots[i] === null) {
          const file = files[fileIndex];
          if (file) {
            newSlots[i] = {
              type: "file",
              data: file,
              previewUrl: URL.createObjectURL(file),
              slotId: createSlotId(),
            };
          }
          fileIndex++;
        }
      }
      return newSlots;
    });
  }, []);

  const handleMultiFileSelect = useCallback((files: ImageFileSelection[]) => {
    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      let fileIndex = 0;
      for (let i = 0; i < TOTAL_IMAGE_SLOTS && fileIndex < files.length; i++) {
        if (newSlots[i] === null) {
          const file = files[fileIndex];
          if (file) {
            newSlots[i] = {
              type: "existing",
              data: file,
              previewUrl: file.filepath,
              slotId: file.id,
            };
          }
          fileIndex++;
        }
      }
      return newSlots;
    });
    setShowFileManager(false);
  }, []);

  const swapImageSlots = useCallback((fromIndex: number, toIndex: number) => {
    if (fromIndex === toIndex) return;
    if (fromIndex < 0 || fromIndex >= TOTAL_IMAGE_SLOTS) return;
    if (toIndex < 0 || toIndex >= TOTAL_IMAGE_SLOTS) return;

    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      const temp = newSlots[fromIndex];
      newSlots[fromIndex] = newSlots[toIndex]!;
      newSlots[toIndex] = temp!;
      return newSlots;
    });

    setImageLinks((prevLinks) => {
      const newLinks = [...prevLinks];
      const temp = newLinks[fromIndex];
      newLinks[fromIndex] = newLinks[toIndex]!;
      newLinks[toIndex] = temp!;
      return newLinks;
    });
  }, []);

  const applyRefresh = useCallback((savedProduct: ProductWithImages) => {
    setImageSlots((prevSlots) => {
      // Instead of replacing all slots, update only what changed
      // This prevents flickering by keeping existing references when possible
      const newSlots: (ProductImageSlot | null)[] = [...prevSlots];

      // Update slots with saved images
      savedProduct.images.slice(0, TOTAL_IMAGE_SLOTS).forEach((pImg, index) => {
        if (pImg.imageFile) {
          const existingSlot = newSlots[index];
          // Only update if the image ID changed or slot was empty
          if (
            !existingSlot ||
            existingSlot.type !== "existing" ||
            existingSlot.slotId !== pImg.imageFile.id
          ) {
            newSlots[index] = {
              type: "existing",
              data: pImg.imageFile,
              previewUrl: pImg.imageFile.filepath,
              slotId: pImg.imageFile.id,
            };
          }
        }
      });

      // Clear slots beyond saved images count
      for (let i = savedProduct.images.length; i < TOTAL_IMAGE_SLOTS; i++) {
        if (newSlots[i]?.type === "file") {
          // Keep temporary file uploads that haven't been saved yet
          continue;
        }
        newSlots[i] = null;
      }

      return newSlots;
    });
    setImageLinks(normalizeImageLinks(savedProduct.imageLinks));
  }, []);

  const setImagesReordering = useCallback(
    (value: boolean) => {
      isReorderingRef.current = value;
      if (!value && pendingRefreshRef.current) {
        const pending = pendingRefreshRef.current;
        pendingRefreshRef.current = null;
        applyRefresh(pending);
      }
    },
    [applyRefresh],
  );

  // Function to refresh state from product (e.g. after save)
  const refreshFromProduct = useCallback(
    (savedProduct: ProductWithImages) => {
      if (isReorderingRef.current) {
        pendingRefreshRef.current = savedProduct;
        if (process.env.NODE_ENV !== "production") {
          console.info("[product-images] Refresh deferred during reorder");
        }
        return;
      }
      applyRefresh(savedProduct);
    },
    [applyRefresh],
  );

  return {
    imageSlots,
    imageLinks,
    showFileManager,
    setShowFileManager,
    handleSlotImageChange,
    handleSlotFileSelect,
    handleSlotDisconnectImage,
    handleMultiImageChange,
    handleMultiFileSelect,
    swapImageSlots,
    setImageLinkAt,
    refreshFromProduct,
    setImagesReordering,
  };
}

"use client";

import React from "react";
import { useQuery, type UseQueryResult } from "@tanstack/react-query";
import type { 
  CatalogRecord, 
  ProductCategory, 
  ProductTag, 
  ProductParameter 
} from "@/features/products/types";

export const productMetadataKeys = {
  catalogs: ["catalogs"] as const,
  categories: (catalogId: string) => ["categories", catalogId] as const,
  tags: (catalogId: string) => ["tags", catalogId] as const,
  parameters: (catalogId: string) => ["parameters", catalogId] as const,
};

export function useCatalogs(): UseQueryResult<CatalogRecord[]> {
  return useQuery({
    queryKey: productMetadataKeys.catalogs,
    queryFn: async (): Promise<CatalogRecord[]> => {
      const res = await fetch("/api/catalogs");
      if (!res.ok) throw new Error("Failed to load catalogs");
      return (await res.json()) as CatalogRecord[];
    },
  });
}

export function useCategories(catalogId: string): UseQueryResult<ProductCategory[]> {
  return useQuery({
    queryKey: productMetadataKeys.categories(catalogId),
    queryFn: async (): Promise<ProductCategory[]> => {
      const res = await fetch(`/api/products/categories?catalogId=${catalogId}`);
      if (!res.ok) throw new Error("Failed to load categories");
      return (await res.json()) as ProductCategory[];
    },
    enabled: !!catalogId,
  });
}

export function useTags(catalogId: string): UseQueryResult<ProductTag[]> {
  return useQuery({
    queryKey: productMetadataKeys.tags(catalogId),
    queryFn: async (): Promise<ProductTag[]> => {
      const res = await fetch(`/api/products/tags?catalogId=${catalogId}`);
      if (!res.ok) throw new Error("Failed to load tags");
      return (await res.json()) as ProductTag[];
    },
    enabled: !!catalogId,
  });
}

export function useParameters(catalogId: string): UseQueryResult<ProductParameter[]> {
  return useQuery({
    queryKey: productMetadataKeys.parameters(catalogId),
    queryFn: async (): Promise<ProductParameter[]> => {
      const res = await fetch(`/api/products/parameters?catalogId=${catalogId}`);
      if (!res.ok) throw new Error("Failed to load parameters");
      return (await res.json()) as ProductParameter[];
    },
    enabled: !!catalogId,
  });
}
// Composite hook that combines all metadata functionality
export function useProductMetadata({
  initialCatalogId,
}: {
  initialCatalogId?: string;
  // Other props ignored for now to fix tsc errors
  [key: string]: any;
}) {
  const catalogsQuery = useCatalogs();
  const [selectedCatalogIds, setSelectedCatalogIds] = React.useState<string[]>([]);
  const [selectedCategoryIds, setSelectedCategoryIds] = React.useState<string[]>([]);
  const [selectedTagIds, setSelectedTagIds] = React.useState<string[]>([]);

  const primaryCatalogId = selectedCatalogIds[0] || initialCatalogId || "";
  const categoriesQuery = useCategories(primaryCatalogId);
  const tagsQuery = useTags(primaryCatalogId);
  const parametersQuery = useParameters(primaryCatalogId);

  const toggleCatalog = (catalogId: string) => {
    setSelectedCatalogIds(prev => 
      prev.includes(catalogId) 
        ? prev.filter(id => id !== catalogId)
        : [...prev, catalogId]
    );
  };

  const toggleCategory = (categoryId: string) => {
    setSelectedCategoryIds(prev => 
      prev.includes(categoryId) 
        ? prev.filter(id => id !== categoryId)
        : [...prev, categoryId]
    );
  };

  const toggleTag = (tagId: string) => {
    setSelectedTagIds(prev => 
      prev.includes(tagId) 
        ? prev.filter(id => id !== tagId)
        : [...prev, tagId]
    );
  };

  return {
    catalogs: catalogsQuery.data || [],
    catalogsLoading: catalogsQuery.isLoading,
    catalogsError: catalogsQuery.error?.message || null,
    selectedCatalogIds,
    toggleCatalog,
    categories: categoriesQuery.data || [],
    categoriesLoading: categoriesQuery.isLoading,
    selectedCategoryIds,
    toggleCategory,
    tags: tagsQuery.data || [],
    tagsLoading: tagsQuery.isLoading,
    selectedTagIds,
    toggleTag,
    parameters: parametersQuery.data || [],
    parametersLoading: parametersQuery.isLoading,
    filteredLanguages: [], // Placeholder
    filteredPriceGroups: [], // Placeholder
  };
}

import { useQuery, useMutation, useQueryClient, type UseQueryResult } from "@tanstack/react-query";
import * as api from "../api/settings";
import { PriceGroup, Catalog, CatalogRecord, ProductCategory, ProductTag, ProductParameter, ProductCategoryWithChildren } from "../types";

export const productSettingsKeys = {
  all: ["product-settings"] as const,
  priceGroups: () => [...productSettingsKeys.all, "price-groups"] as const,
  catalogs: () => [...productSettingsKeys.all, "catalogs"] as const,
  categories: (catalogId: string | null) => [...productSettingsKeys.all, "categories", catalogId] as const,
  tags: (catalogId: string | null) => [...productSettingsKeys.all, "tags", catalogId] as const,
  parameters: (catalogId: string | null) => [...productSettingsKeys.all, "parameters", catalogId] as const,
};

export function usePriceGroups() {
  return useQuery({
    queryKey: productSettingsKeys.priceGroups(),
    queryFn: api.getPriceGroups,
  });
}

export function useCatalogs() {
  return useQuery<CatalogRecord[], Error>({
    queryKey: productSettingsKeys.catalogs(),
    queryFn: api.getCatalogs,
  });
}

export function useCategories(catalogId: string | null): UseQueryResult<ProductCategoryWithChildren[], Error> {
  return useQuery({
    queryKey: productSettingsKeys.categories(catalogId),
    queryFn: () => api.getCategories(catalogId),
    enabled: !!catalogId,
  });
}

export function useTags(catalogId: string | null) {
  return useQuery({
    queryKey: productSettingsKeys.tags(catalogId),
    queryFn: () => api.getTags(catalogId),
    enabled: !!catalogId,
  });
}

export function useParameters(catalogId: string | null) {
  return useQuery({
    queryKey: productSettingsKeys.parameters(catalogId),
    queryFn: () => api.getParameters(catalogId),
    enabled: !!catalogId,
  });
}

