import "server-only";

import OpenAI from "openai";
import type { ChatCompletionContentPart } from "openai/resources/chat/completions";
import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { getImageFileRepository } from "@/features/files/server";
import type { ProductFormData } from "@/features/products/types";
import type { ImageFileRecord } from "@/shared/types/files";
import fs from "fs/promises";
import path from "path";
import {
  badRequestError,
  configurationError,
  operationFailedError,
} from "@/shared/errors/app-error";

const OLLAMA_BASE_URL = process.env.OLLAMA_BASE_URL || "http://localhost:11434";

// AI-related settings that should be read from MongoDB when available
const AI_SETTINGS_KEYS = new Set([
  "ai_vision_model",
  "ai_vision_user_prompt",
  "ai_vision_prompt",
  "ai_vision_output_enabled",
  "openai_model",
  "openai_api_key",
  "description_generation_user_prompt",
  "description_generation_prompt",
  "ai_generation_output_enabled",
]);

interface MongoSetting {
  _id: string;
  value: string;
}

export async function getSettingValue(key: string): Promise<string | null> {
  let value: string | null = null;

  // For AI settings, prefer MongoDB if available
  if (AI_SETTINGS_KEYS.has(key) && process.env.MONGODB_URI) {
    try {
      const mongo = await getMongoDb();
      const doc = await mongo
        .collection<MongoSetting>("settings")
        .findOne({ _id: key });
      if (doc && typeof doc.value === "string") {
        value = doc.value;
        return value; // Return immediately if found in MongoDB
      }
    } catch (err) {
      console.warn(`Mongo setting fetch failed for ${key}:`, err);
    }
  }

  // Fall back to Prisma
  if (!value && process.env.DATABASE_URL) {
    try {
      const setting = await prisma.setting.findUnique({
        where: { key },
        select: { value: true },
      });
      if (setting) value = setting.value;
    } catch (err) {
      console.warn(`Prisma setting fetch failed for ${key}:`, err);
    }
  }

  // If still not found and not an AI setting, try MongoDB as fallback
  if (!value && !AI_SETTINGS_KEYS.has(key) && process.env.MONGODB_URI) {
    try {
      const mongo = await getMongoDb();
      const doc = await mongo
        .collection<MongoSetting>("settings")
        .findOne({ _id: key });
      if (doc && typeof doc.value === "string") {
        value = doc.value;
      }
    } catch (err) {
      console.warn(`Mongo fallback setting fetch failed for ${key}:`, err);
    }
  }

  return value;
}

function getClient(
  modelName: string,
  apiKey: string | null,
): { openai: OpenAI; isOllama: boolean } {
  // Check if it's a real OpenAI model (not gpt-oss or other Ollama variants)
  const modelLower = modelName.toLowerCase();
  const isOpenAI =
    (modelLower.startsWith("gpt-") && !modelLower.includes("oss")) ||
    modelLower.startsWith("ft:gpt-") ||
    modelLower.startsWith("o1-");

  if (isOpenAI) {
    if (!apiKey) {
      throw configurationError("OpenAI API key is missing for GPT model.");
    }
    return { openai: new OpenAI({ apiKey }), isOllama: false };
  }

  // All other models use Ollama
  return {
    openai: new OpenAI({
      baseURL: `${OLLAMA_BASE_URL}/v1`,
      apiKey: "ollama",
    }),
    isOllama: true,
  };
}

interface GenerateProductDescriptionResult {
  analysisInitial: string;
  analysisFinal: string;
  descriptionInitial: string;
  descriptionFinal: string;
  description: string;
  analysis: string;
  visionModel: string;
  generationModel: string;
  visionOutputEnabled: boolean;
  generationOutputEnabled: boolean;
}

export async function generateProductDescription(params: {
  productData: ProductFormData;
  imageUrls?: string[] | undefined;
  visionOutputEnabled?: boolean | undefined;
  generationOutputEnabled?: boolean | undefined;
}): Promise<GenerateProductDescriptionResult> {
  const {
    productData,
    imageUrls = [],
    visionOutputEnabled,
    generationOutputEnabled,
  } = params;

  if (!productData?.name_en) {
    throw badRequestError("Product name is required", { field: "name_en" });
  }

  const [
    apiKeySetting,
    visionModelSetting,
    visionInputPromptSetting,
    visionOutputPromptSetting,
    visionOutputEnabledSetting,
    generationModelSetting,
    generationInputPromptSetting,
    generationOutputPromptSetting,
    generationOutputEnabledSetting,
  ] = await Promise.all([
    getSettingValue("openai_api_key"),
    getSettingValue("ai_vision_model"),
    getSettingValue("ai_vision_user_prompt"),
    getSettingValue("ai_vision_prompt"),
    getSettingValue("ai_vision_output_enabled"),
    getSettingValue("openai_model"),
    getSettingValue("description_generation_user_prompt"),
    getSettingValue("description_generation_prompt"),
    getSettingValue("ai_generation_output_enabled"),
  ]);

  const apiKey = apiKeySetting ?? process.env.OPENAI_API_KEY ?? null;
  const visionModel = visionModelSetting?.trim() || "gemma3:27b";
  const visionInputPrompt =
    visionInputPromptSetting?.trim() || "Analyze these product images...";
  const visionOutputPrompt = visionOutputPromptSetting?.trim() || "";
  const isVisionOutputEnabled =
    visionOutputEnabled !== undefined
      ? visionOutputEnabled
      : visionOutputEnabledSetting === "true";

  const generationModel = generationModelSetting?.trim() || "qwen3-vl:30b";
  const generationInputPrompt =
    generationInputPromptSetting?.trim() ||
    "Generate description for [name_en]";
  const generationOutputPrompt = generationOutputPromptSetting?.trim() || "";
  const isGenerationOutputEnabled =
    generationOutputEnabled !== undefined
      ? generationOutputEnabled
      : generationOutputEnabledSetting === "true";

  const processPrompt = (
    text: string,
    currentResult: string = "",
    analysisResult: string = "",
    descriptionInitial: string = "",
  ): { text: string; attachImages: boolean } => {
    let processed = text;
    const hasImagesPlaceholder = processed.includes("[images]");
    processed = processed.replace(/\[analysis\]/g, analysisResult);
    processed = processed.replace(/\[imageAnalysis\]/g, analysisResult);
    processed = processed.replace(/\[description\]/g, descriptionInitial);
    processed = processed.replace(/\[result\]/g, currentResult);
    processed = processed.replace(/\[initialResult\]/g, currentResult);
    processed = processed.replace(/\[images\]/g, "");

    if (productData) {
      for (const key in productData) {
        if (Object.prototype.hasOwnProperty.call(productData, key)) {
          const value = productData[key as keyof ProductFormData];
          if (value !== null && value !== undefined) {
            const stringValue =
              typeof value === "object" ? JSON.stringify(value) : String(value);
            processed = processed.replace(
              new RegExp(`\\[${key}\\]`, "g"),
              stringValue,
            );
          }
        }
      }
    }
    return { text: processed.trim(), attachImages: hasImagesPlaceholder };
  };

  let processedImages: ChatCompletionContentPart[] = [];
  if (imageUrls.length > 0) {
    const imageFileRepository = await getImageFileRepository();
    const imageFiles = await imageFileRepository.listImageFiles();
    const imageFileMap = new Map(
      imageFiles.map((file: ImageFileRecord) => [file.filepath, file]),
    );

    const imagePromises = imageUrls.map(async (item: string) => {
      try {
        let base64Image: string;
        let mimetype: string = "image/jpeg";
        if (item.startsWith("http")) {
          const res = await fetch(item);
          if (!res.ok) return null;
          const buffer = Buffer.from(await res.arrayBuffer());
          base64Image = buffer.toString("base64");
          mimetype = res.headers.get("content-type") || "image/jpeg";
        } else {
          const imagePath = path.join(process.cwd(), "public", item);
          const buffer = await fs.readFile(imagePath);
          base64Image = buffer.toString("base64");
          const record = imageFileMap.get(item);
          if (record) mimetype = record.mimetype;
        }
        return {
          type: "image_url" as const,
          image_url: { url: `data:${mimetype};base64,${base64Image}` },
        } as ChatCompletionContentPart;
      } catch {
        return null;
      }
    });
    processedImages = (await Promise.all(imagePromises)).filter(
      (img): img is ChatCompletionContentPart => img !== null,
    );
  }

  let analysisInitial = "";
  let analysisFinal = "";
  const { openai: visionClient, isOllama: isVisionOllama } = getClient(
    visionModel,
    apiKey,
  );

  try {
    const prompt1_1 = processPrompt(visionInputPrompt);
    const content1_1: ChatCompletionContentPart[] = [
      { type: "text", text: prompt1_1.text },
    ];
    if (prompt1_1.attachImages) content1_1.push(...processedImages);

    const visionCompletion = await visionClient.chat.completions.create({
      model: visionModel,
      messages: [
        { role: "system", content: "You are an AI assistant." },
        { role: "user", content: content1_1 },
      ],
      max_tokens: 500,
    });
    analysisInitial =
      visionCompletion.choices[0]?.message.content?.trim() || "";

    if (isVisionOutputEnabled && visionOutputPrompt) {
      const prompt1_2 = processPrompt(
        visionOutputPrompt,
        analysisInitial,
        analysisInitial,
      );
      const content1_2: ChatCompletionContentPart[] = [
        { type: "text", text: prompt1_2.text },
      ];
      if (prompt1_2.attachImages) content1_2.push(...processedImages);
      const refineCompletion = await visionClient.chat.completions.create({
        model: visionModel,
        messages: [
          { role: "system", content: "You are an AI assistant." },
          { role: "user", content: content1_2 },
        ],
        max_tokens: 500,
      });
      analysisFinal =
        refineCompletion.choices[0]?.message.content?.trim() || "";
    }
  } catch (error) {
    const errorMessage =
      error instanceof Error ? error.message : "Unknown error";
    const isConnectionError =
      errorMessage.includes("ECONNREFUSED") ||
      errorMessage.includes("fetch failed") ||
      errorMessage.includes("failed to fetch");

    if (isVisionOllama && isConnectionError) {
      throw operationFailedError(
        `Description generation failed: Could not connect to Ollama server at ${OLLAMA_BASE_URL}. Please ensure the Ollama server is running and accessible.`,
        undefined,
        {
          originalError: errorMessage,
          url: OLLAMA_BASE_URL,
          model: visionModel,
        },
      );
    }
    throw error;
  }

  const visionResultForNext = analysisFinal || analysisInitial;
  const { openai: generationClient, isOllama: isGenerationOllama } = getClient(
    generationModel,
    apiKey,
  );
  let descriptionInitial = "";
  let descriptionFinal = "";

  try {
    const prompt2_1 = processPrompt(
      generationInputPrompt,
      visionResultForNext,
      visionResultForNext,
    );
    const content2_1: ChatCompletionContentPart[] = [
      { type: "text", text: prompt2_1.text },
    ];
    if (prompt2_1.attachImages) content2_1.push(...processedImages);
    const genCompletion = await generationClient.chat.completions.create({
      model: generationModel,
      messages: [
        { role: "system", content: "You are a helpful assistant." },
        { role: "user", content: content2_1 },
      ],
      max_tokens: 1000,
    });
    descriptionInitial =
      genCompletion.choices[0]?.message.content?.trim() || "";

    if (isGenerationOutputEnabled && generationOutputPrompt) {
      const prompt2_2 = processPrompt(
        generationOutputPrompt,
        descriptionInitial,
        visionResultForNext,
        descriptionInitial,
      );
      const content2_2: ChatCompletionContentPart[] = [
        { type: "text", text: prompt2_2.text },
      ];
      if (prompt2_2.attachImages) content2_2.push(...processedImages);
      const refineGenCompletion =
        await generationClient.chat.completions.create({
          model: generationModel,
          messages: [
            { role: "system", content: "You are a helpful assistant." },
            { role: "user", content: content2_2 },
          ],
          max_tokens: 1000,
        });
      descriptionFinal =
        refineGenCompletion.choices[0]?.message.content?.trim() || "";
    }
  } catch (error) {
    const errorMessage =
      error instanceof Error ? error.message : "Unknown error";
    const isConnectionError =
      errorMessage.includes("ECONNREFUSED") ||
      errorMessage.includes("fetch failed") ||
      errorMessage.includes("failed to fetch");

    if (isGenerationOllama && isConnectionError) {
      throw operationFailedError(
        `Description generation failed: Could not connect to Ollama server at ${OLLAMA_BASE_URL}. Please ensure the Ollama server is running and accessible.`,
        undefined,
        {
          originalError: errorMessage,
          url: OLLAMA_BASE_URL,
          model: generationModel,
        },
      );
    }
    throw error;
  }

  return {
    analysisInitial,
    analysisFinal,
    descriptionInitial,
    descriptionFinal,
    description: descriptionFinal || descriptionInitial,
    analysis: analysisFinal || analysisInitial,
    // Include model information for job tracking
    visionModel,
    generationModel,
    visionOutputEnabled: isVisionOutputEnabled,
    generationOutputEnabled: isGenerationOutputEnabled,
  };
}

import "server-only";

import { randomUUID } from "crypto";
import type { Document, Filter, WithId } from "mongodb";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { conflictError } from "@/shared/errors/app-error";
import type { ProductRecord, ProductWithImages, ProductImageRecord, CatalogRecord } from "@/features/products/types";
import type { ImageFileRecord } from "@/shared/types/files";
import { mongoCatalogRepository } from "@/features/products/services/catalog-repository/mongo-catalog-repository";
import { mongoImageFileRepository } from "@/features/files/server";
import type {
  CreateProductInput,
  ProductFilters,
  ProductRepository,
  UpdateProductInput,
} from "@/features/products/types/services/product-repository";

type ProductDocument = ProductRecord & {
  _id: string;
  images?: ProductWithImages["images"];
  catalogs?: ProductWithImages["catalogs"];
};

const productCollectionName = "products";

const toProductResponse = (doc: WithId<ProductDocument>): ProductWithImages => ({
  id: doc.id ?? doc._id,
  sku: doc.sku ?? null,
  baseProductId: doc.baseProductId ?? null,
  defaultPriceGroupId: doc.defaultPriceGroupId ?? null,
  ean: doc.ean ?? null,
  gtin: doc.gtin ?? null,
  asin: doc.asin ?? null,
  name_en: doc.name_en ?? null,
  name_pl: doc.name_pl ?? null,
  name_de: doc.name_de ?? null,
  description_en: doc.description_en ?? null,
  description_pl: doc.description_pl ?? null,
  description_de: doc.description_de ?? null,
  supplierName: doc.supplierName ?? null,
  supplierLink: doc.supplierLink ?? null,
  priceComment: doc.priceComment ?? null,
  stock: doc.stock ?? null,
  price: doc.price ?? null,
  sizeLength: doc.sizeLength ?? null,
  sizeWidth: doc.sizeWidth ?? null,
  weight: doc.weight ?? null,
  length: doc.length ?? null,
  parameters: Array.isArray(doc.parameters) ? doc.parameters : [],
  imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
  createdAt: doc.createdAt ?? new Date(),
  updatedAt: doc.updatedAt ?? new Date(),
  images: Array.isArray(doc.images) ? doc.images : [],
  catalogs: Array.isArray(doc.catalogs) ? doc.catalogs : [],
});

const toProductBase = (doc: ProductDocument): ProductRecord => ({
  id: doc.id ?? doc._id,
  sku: doc.sku ?? null,
  baseProductId: doc.baseProductId ?? null,
  defaultPriceGroupId: doc.defaultPriceGroupId ?? null,
  ean: doc.ean ?? null,
  gtin: doc.gtin ?? null,
  asin: doc.asin ?? null,
  name_en: doc.name_en ?? null,
  name_pl: doc.name_pl ?? null,
  name_de: doc.name_de ?? null,
  description_en: doc.description_en ?? null,
  description_pl: doc.description_pl ?? null,
  description_de: doc.description_de ?? null,
  supplierName: doc.supplierName ?? null,
  supplierLink: doc.supplierLink ?? null,
  priceComment: doc.priceComment ?? null,
  stock: doc.stock ?? null,
  price: doc.price ?? null,
  sizeLength: doc.sizeLength ?? null,
  sizeWidth: doc.sizeWidth ?? null,
  weight: doc.weight ?? null,
  length: doc.length ?? null,
  parameters: Array.isArray(doc.parameters) ? doc.parameters : [],
  imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
  createdAt: doc.createdAt ?? new Date(),
  updatedAt: doc.updatedAt ?? new Date(),
});

const buildSearchFilter = (filters: ProductFilters): Filter<ProductDocument> => {
  const filter: Filter<ProductDocument> = {};

  if (filters.sku) {
    filter.sku = { $regex: filters.sku, $options: "i" };
  }

  if (filters.search) {
    const regex = { $regex: filters.search, $options: "i" };
    // If a specific language is selected, only search in that language's name field
    if (filters.searchLanguage) {
      // searchLanguage is like "name_en", "name_pl", "name_de"
      filter.$or = [{ [filters.searchLanguage]: regex }];
    } else {
      // Search all language fields
      filter.$or = [
        { name_en: regex },
        { name_pl: regex },
        { name_de: regex },
        { description_en: regex },
        { description_pl: regex },
        { description_de: regex },
      ];
    }
  }

  if (filters.minPrice || filters.maxPrice) {
    filter.price = {};
    if (filters.minPrice) {
      filter.price.$gte = parseInt(filters.minPrice, 10);
    }
    if (filters.maxPrice) {
      filter.price.$lte = parseInt(filters.maxPrice, 10);
    }
  }

  if (filters.startDate || filters.endDate) {
    filter.createdAt = {};
    if (filters.startDate) {
      filter.createdAt.$gte = new Date(filters.startDate);
    }
    if (filters.endDate) {
      filter.createdAt.$lte = new Date(filters.endDate);
    }
  }

  if (filters.catalogId) {
    if (filters.catalogId === "unassigned") {
      filter.catalogs = { $size: 0 };
    } else {
      filter.catalogs = { $elemMatch: { catalogId: filters.catalogId } };
    }
  }

  return filter;
};

export const mongoProductRepository: ProductRepository = {
  async getProducts(filters: ProductFilters) {
    const db = await getMongoDb();
    const page = filters.page ? parseInt(filters.page, 10) : undefined;
    const pageSize = filters.pageSize ? parseInt(filters.pageSize, 10) : undefined;
    const skip = page && pageSize ? (page - 1) * pageSize : undefined;
    const limit = pageSize;

    let cursor = db
      .collection<ProductDocument>(productCollectionName)
      .find(buildSearchFilter(filters))
      .sort({ createdAt: -1 });

    if (skip !== undefined) {
      cursor = cursor.skip(skip);
    }
    if (limit !== undefined) {
      cursor = cursor.limit(limit);
    }

    const docs = await cursor.toArray();
    return docs.map(toProductResponse);
  },

  async countProducts(filters: ProductFilters) {
    const db = await getMongoDb();
    return db
      .collection<ProductDocument>(productCollectionName)
      .countDocuments(buildSearchFilter(filters));
  },

  async getProductById(id: string) {
    const db = await getMongoDb();
    const doc = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ $or: [{ _id: id }, { id }] });
    return doc ? toProductResponse({ ...doc, _id: doc._id }) : null;
  },

  async getProductBySku(sku: string) {
    const db = await getMongoDb();
    const doc = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ sku });
    return doc ? toProductBase(doc) : null;
  },

  async findProductByBaseId(baseProductId: string) {
    const db = await getMongoDb();
    const doc = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ baseProductId });
    return doc ? toProductBase(doc) : null;
  },

  async createProduct(data: CreateProductInput) {
    const db = await getMongoDb();
    const now = new Date();
    const id = randomUUID();
    if (data.sku) {
      const existing = await db
        .collection<ProductDocument>(productCollectionName)
        .findOne({ sku: data.sku });
      if (existing) {
        throw conflictError("A product with this SKU already exists.", {
          sku: data.sku,
          productId: existing.id ?? existing._id,
        });
      }
    }
    const document: ProductDocument = {
      _id: id,
      id,
      sku: typeof data.sku === "string" ? data.sku : null,
      baseProductId:
        typeof data.baseProductId === "string" ? data.baseProductId : null,
      defaultPriceGroupId:
        typeof data.defaultPriceGroupId === "string"
          ? data.defaultPriceGroupId
          : null,
      ean: typeof data.ean === "string" ? data.ean : null,
      gtin: typeof data.gtin === "string" ? data.gtin : null,
      asin: typeof data.asin === "string" ? data.asin : null,
      name_en: typeof data.name_en === "string" ? data.name_en : null,
      name_pl: typeof data.name_pl === "string" ? data.name_pl : null,
      name_de: typeof data.name_de === "string" ? data.name_de : null,
      description_en:
        typeof data.description_en === "string" ? data.description_en : null,
      description_pl:
        typeof data.description_pl === "string" ? data.description_pl : null,
      description_de:
        typeof data.description_de === "string" ? data.description_de : null,
      supplierName:
        typeof data.supplierName === "string" ? data.supplierName : null,
      supplierLink:
        typeof data.supplierLink === "string" ? data.supplierLink : null,
      priceComment:
        typeof data.priceComment === "string" ? data.priceComment : null,
      stock: typeof data.stock === "number" ? data.stock : null,
      price: typeof data.price === "number" ? data.price : null,
      sizeLength: typeof data.sizeLength === "number" ? data.sizeLength : null,
      sizeWidth: typeof data.sizeWidth === "number" ? data.sizeWidth : null,
      weight: typeof data.weight === "number" ? data.weight : null,
      length: typeof data.length === "number" ? data.length : null,
      parameters: Array.isArray(data.parameters) ? data.parameters.map((p) => ({ parameterId: p.parameterId, value: p.value || "" })) : [],
      imageLinks: Array.isArray(data.imageLinks) ? data.imageLinks : [],
      createdAt: now,
      updatedAt: now,
      images: [],
      catalogs: [],
    };
    await db
      .collection<ProductDocument>(productCollectionName)
      .insertOne(document);
    return toProductBase(document);
  },

  async updateProduct(id: string, data: UpdateProductInput) {
    const db = await getMongoDb();
    const updateDoc: Partial<ProductDocument> = {
      updatedAt: new Date(),
      ...(data.sku !== undefined ? { sku: data.sku ?? null } : null),
      ...(data.baseProductId !== undefined
        ? { baseProductId: data.baseProductId ?? null }
        : null),
      ...(data.defaultPriceGroupId !== undefined
        ? { defaultPriceGroupId: data.defaultPriceGroupId ?? null }
        : null),
      ...(data.ean !== undefined ? { ean: data.ean ?? null } : null),
      ...(data.gtin !== undefined ? { gtin: data.gtin ?? null } : null),
      ...(data.asin !== undefined ? { asin: data.asin ?? null } : null),
      ...(data.name_en !== undefined ? { name_en: data.name_en ?? null } : null),
      ...(data.name_pl !== undefined ? { name_pl: data.name_pl ?? null } : null),
      ...(data.name_de !== undefined ? { name_de: data.name_de ?? null } : null),
      ...(data.description_en !== undefined
        ? { description_en: data.description_en ?? null }
        : null),
      ...(data.description_pl !== undefined
        ? { description_pl: data.description_pl ?? null }
        : null),
      ...(data.description_de !== undefined
        ? { description_de: data.description_de ?? null }
        : null),
      ...(data.supplierName !== undefined
        ? { supplierName: data.supplierName ?? null }
        : null),
      ...(data.supplierLink !== undefined
        ? { supplierLink: data.supplierLink ?? null }
        : null),
      ...(data.priceComment !== undefined
        ? { priceComment: data.priceComment ?? null }
        : null),
      ...(data.stock !== undefined ? { stock: data.stock ?? null } : null),
      ...(data.price !== undefined ? { price: data.price ?? null } : null),
      ...(data.sizeLength !== undefined
        ? { sizeLength: data.sizeLength ?? null }
        : null),
      ...(data.sizeWidth !== undefined
        ? { sizeWidth: data.sizeWidth ?? null }
        : null),
      ...(data.weight !== undefined ? { weight: data.weight ?? null } : null),
      ...(data.length !== undefined ? { length: data.length ?? null } : null),
      ...(data.parameters !== undefined
        ? {
            parameters: Array.isArray(data.parameters) ? data.parameters.map((p) => ({ parameterId: p.parameterId, value: p.value || "" })) : [],
          }
        : null),
      ...(data.imageLinks !== undefined
        ? {
            imageLinks: Array.isArray(data.imageLinks)
              ? data.imageLinks
              : [],
          }
        : null),
    };
    const result = await db
      .collection<ProductDocument>(productCollectionName)
      .findOneAndUpdate(
        { $or: [{ _id: id }, { id }] },
        { $set: updateDoc },
        { returnDocument: "after" }
      );
    if (!result) return null;
    return toProductBase({
      ...(result as ProductDocument),
      id: (result as ProductDocument).id ?? id,
    });
  },

  async deleteProduct(id: string) {
    const db = await getMongoDb();
    const result = await db
      .collection<ProductDocument>(productCollectionName)
      .findOneAndDelete({ $or: [{ _id: id }, { id }] });
    if (!result) return null;
    return toProductBase({
      ...(result as ProductDocument),
      id: (result as ProductDocument).id ?? id,
    });
  },

  async duplicateProduct(id: string, sku: string) {
    const db = await getMongoDb();
    const existing = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ $or: [{ _id: id }, { id }] });
    if (!existing) return null;

    const skuExists = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ sku });
    if (skuExists) {
      throw conflictError("A product with this SKU already exists.", {
        sku,
        productId: skuExists.id ?? skuExists._id,
      });
    }

    const now = new Date();
    const duplicatedId = randomUUID();
    const document: ProductDocument = {
      _id: duplicatedId,
      id: duplicatedId,
      sku,
      baseProductId: null,
      defaultPriceGroupId: existing.defaultPriceGroupId ?? null,
      ean: existing.ean ?? null,
      gtin: existing.gtin ?? null,
      asin: existing.asin ?? null,
      name_en: existing.name_en ?? null,
      name_pl: existing.name_pl ?? null,
      name_de: existing.name_de ?? null,
      description_en: existing.description_en ?? null,
      description_pl: existing.description_pl ?? null,
      description_de: existing.description_de ?? null,
      supplierName: existing.supplierName ?? null,
      supplierLink: existing.supplierLink ?? null,
      priceComment: existing.priceComment ?? null,
      stock: existing.stock ?? null,
      price: existing.price ?? null,
      sizeLength: existing.sizeLength ?? null,
      sizeWidth: existing.sizeWidth ?? null,
      weight: existing.weight ?? null,
      length: existing.length ?? null,
      parameters: Array.isArray(existing.parameters) ? existing.parameters : [],
      imageLinks: Array.isArray(existing.imageLinks) ? existing.imageLinks : [],
      createdAt: now,
      updatedAt: now,
      images: [],
      catalogs: [],
    };

    await db
      .collection<ProductDocument>(productCollectionName)
      .insertOne(document);
    return toProductBase(document);
  },

  async addProductImages(productId: string, imageFileIds: string[]) {
    if (imageFileIds.length === 0) return;
    const db = await getMongoDb();
    const imageFiles = await mongoImageFileRepository.findImageFilesByIds(
      imageFileIds
    );
    const now = new Date();
    const incoming = imageFiles.map((imageFile: ImageFileRecord) => ({
      productId,
      imageFileId: imageFile.id,
      assignedAt: now,
      imageFile,
    }));
    const product = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ $or: [{ _id: productId }, { id: productId }] });
    const existing = Array.isArray(product?.images) ? product.images : [];
    const merged = [
      ...existing.filter(
        (entry: ProductImageRecord) =>
          !incoming.some(
            (next: ProductImageRecord) => next.imageFileId === entry.imageFileId
          )
      ),
      ...incoming,
    ];
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { images: merged, updatedAt: new Date() } }
      );
  },

  async replaceProductCatalogs(productId: string, catalogIds: string[]) {
    const db = await getMongoDb();
    if (catalogIds.length === 0) {
      await db
        .collection<ProductDocument>(productCollectionName)
        .updateOne(
          { $or: [{ _id: productId }, { id: productId }] },
          { $set: { catalogs: [], updatedAt: new Date() } }
        );
      return;
    }
    const uniqueIds = Array.from(new Set(catalogIds));
    const catalogs = await mongoCatalogRepository.getCatalogsByIds(uniqueIds);
    const now = new Date();
    const catalogEntries = catalogs.map((catalog: CatalogRecord) => ({
      productId,
      catalogId: catalog.id,
      assignedAt: now,
      catalog,
    }));
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { catalogs: catalogEntries, updatedAt: new Date() } }
      );
  },

  async replaceProductCategories(productId: string, categoryIds: string[]) {
    const db = await getMongoDb();
    if (categoryIds.length === 0) {
      await db
        .collection<ProductDocument>(productCollectionName)
        .updateOne(
          { $or: [{ _id: productId }, { id: productId }] },
          { $set: { categories: [], updatedAt: new Date() } }
        );
      return;
    }
    const uniqueIds = Array.from(new Set(categoryIds));
    const categories = await db
      .collection("product_categories")
      .find({ id: { $in: uniqueIds } })
      .toArray();
    const now = new Date();
    const categoryEntries = categories.map((category: Document) => ({
      productId,
      categoryId: (category as unknown as { id: string }).id,
      assignedAt: now,
    }));
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { categories: categoryEntries, updatedAt: new Date() } }
      );
  },

  async replaceProductTags(productId: string, tagIds: string[]) {
    const db = await getMongoDb();
    if (tagIds.length === 0) {
      await db
        .collection<ProductDocument>(productCollectionName)
        .updateOne(
          { $or: [{ _id: productId }, { id: productId }] },
          { $set: { tags: [], updatedAt: new Date() } }
        );
      return;
    }
    const uniqueIds = Array.from(new Set(tagIds));
    const tags = await db
      .collection("product_tags")
      .find({ id: { $in: uniqueIds } })
      .toArray();
    const now = new Date();
    const tagEntries = tags.map((tag: Document) => ({
      productId,
      tagId: (tag as unknown as { id: string }).id,
      assignedAt: now,
    }));
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { tags: tagEntries, updatedAt: new Date() } }
      );
  },

  async removeProductImage(productId: string, imageFileId: string) {
    const db = await getMongoDb();
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        {
          $pull: {
            images: {
              imageFileId,
            },
          },
        }
      );
  },

  async countProductsByImageFileId(imageFileId: string) {
    const db = await getMongoDb();
    return db
      .collection<ProductDocument>(productCollectionName)
      .countDocuments({ "images.imageFileId": imageFileId });
  },
};

import "server-only";
/* eslint-disable @typescript-eslint/explicit-function-return-type, @typescript-eslint/explicit-module-boundary-types, @typescript-eslint/typedef */

import { ErrorSystem } from "@/features/observability/server";
// This service encapsulates all business logic for managing products.

import fs from "fs/promises";
import path from "path";
import {
  productCreateSchema,
  productUpdateSchema,
} from "@/features/products/validations";
import { getDiskPathFromPublicPath, uploadFile } from "@/features/files/server";
import { getProductRepository } from "@/features/products/services/product-repository";
import type {
  ProductFilters,
  ProductRepository,
} from "@/features/products/types/services/product-repository";
import { getImageFileRepository } from "@/features/files/server";
import type { ImageFileRepository } from "@/features/files/types/services/image-file-repository";
import { getCatalogRepository } from "@/features/products/services/catalog-repository";
import { badRequestError } from "@/shared/errors/app-error";
import type {
  ProductWithImages,
  ProductImageRecord,
  ProductRecord,
} from "@/features/products/types";

const resolveProductRepository = async (): Promise<ProductRepository> =>
  getProductRepository();
const resolveImageFileRepository = async (): Promise<ImageFileRepository> =>
  getImageFileRepository();

/**
 * Retrieves a list of products based on the provided filters.
 * @param filters - The filter criteria.
 * @returns A list of products.
 */
async function getProducts(
  filters: ProductFilters,
): Promise<ProductWithImages[]> {
  const productRepository = await resolveProductRepository();
  const products = await productRepository.getProducts(filters);

  return Promise.all(
    products.map(
      async (product: ProductWithImages): Promise<ProductWithImages> => {
        if (!product.images?.length) {
          return product;
        }

        const filteredImages = await Promise.all(
          product.images.map(
            async (
              image: ProductImageRecord,
            ): Promise<ProductImageRecord | null> => {
              const filepath = image.imageFile?.filepath;
              if (!filepath) {
                return null;
              }

              if (/^(https?:|data:)/i.test(filepath)) {
                return image;
              }

              try {
                await fs.access(getDiskPathFromPublicPath(filepath));
                return image;
              } catch {
                return null;
              }
            },
          ),
        );

        return {
          ...product,
          images: filteredImages.filter(
            (img: ProductImageRecord | null): img is ProductImageRecord =>
              img !== null,
          ),
        };
      },
    ),
  );
}

/**
 * Counts the total number of products based on filters.
 * @param filters - The filter criteria.
 * @returns The total count.
 */
async function countProducts(filters: ProductFilters): Promise<number> {
  const productRepository = await resolveProductRepository();
  return productRepository.countProducts(filters);
}

/**
 * Retrieves a single product by its ID.
 * @param id - The ID of the product to retrieve.
 * @returns The product, or null if not found.
 */
async function getProductById(id: string): Promise<ProductWithImages | null> {
  const productRepository = await resolveProductRepository();
  return productRepository.getProductById(id);
}

async function getProductBySku(sku: string): Promise<ProductWithImages | null> {
  const productRepository = await resolveProductRepository();
  const product = await productRepository.getProductBySku(sku);
  if (!product) return null;
  return getProductById(product.id);
}

/**
 * Creates a new product.
 * @param formData - The product data from the form.
 * @returns The newly created product.
 */
async function createProduct(
  formData: FormData,
): Promise<ProductWithImages | null> {
  await ErrorSystem.logInfo("Creating product...");
  try {
    const validatedData = productCreateSchema.parse(
      Object.fromEntries(formData.entries()),
    );
    await ErrorSystem.logInfo("Validated data", { validatedData });
    const productRepository = await resolveProductRepository();
    const product = await productRepository.createProduct(validatedData);

    const images = formData.getAll("images") as File[];
    const imageFileIds = formData.getAll("imageFileIds") as string[];
    const catalogIds = normalizeCatalogIds(formData.getAll("catalogIds"));
    const categoryIds = normalizeCategoryIds(formData.getAll("categoryIds"));
    const tagIds = normalizeTagIds(formData.getAll("tagIds"));
    await linkImagesToProduct(
      product.id,
      images,
      imageFileIds,
      validatedData.sku,
    );
    await updateProductCatalogs(product.id, catalogIds);
    await updateProductCategories(product.id, categoryIds);
    await updateProductTags(product.id, tagIds);

    return await getProductById(product.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "createProduct",
    });
    throw error;
  }
}

/**
 * Updates an existing product.
 * @param id - The ID of the product to update.
 * @param formData - The updated product data from the form.
 * @returns The updated product, or null if not found.
 */
async function updateProduct(
  id: string,
  formData: FormData,
): Promise<ProductWithImages | null> {
  await ErrorSystem.logInfo(`Updating product ${id}...`);
  try {
    const validatedData = productUpdateSchema.parse(
      Object.fromEntries(formData.entries()),
    );
    await ErrorSystem.logInfo("Validated data", { validatedData });
    const productRepository = await resolveProductRepository();
    const updatedProduct = await productRepository.updateProduct(
      id,
      validatedData,
    );
    if (!updatedProduct) return null;

    const images = formData.getAll("images") as File[];
    const imageFileIds = formData.getAll("imageFileIds") as string[];
    await linkImagesToProduct(id, images, imageFileIds, validatedData.sku);
    if (validatedData.sku) {
      await moveLinkedTempImagesToSku(id, validatedData.sku);
    }

    // Only update catalogs/categories/tags if explicitly provided in formData
    if (formData.has("catalogIds")) {
      const catalogIds = normalizeCatalogIds(formData.getAll("catalogIds"));
      await updateProductCatalogs(id, catalogIds);
    }
    if (formData.has("categoryIds")) {
      const categoryIds = normalizeCategoryIds(formData.getAll("categoryIds"));
      await updateProductCategories(id, categoryIds);
    }
    if (formData.has("tagIds")) {
      const tagIds = normalizeTagIds(formData.getAll("tagIds"));
      await updateProductTags(id, tagIds);
    }

    return await getProductById(updatedProduct.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "updateProduct",
      productId: id,
    });
    throw error;
  }
}

/**
 * Deletes a product.
 * @param id - The ID of the product to delete.
 * @returns The deleted product, or null if not found.
 */
async function deleteProduct(id: string): Promise<ProductRecord | null> {
  await ErrorSystem.logInfo(`Deleting product ${id}...`);
  try {
    const productRepository = await resolveProductRepository();
    return await productRepository.deleteProduct(id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "deleteProduct",
      productId: id,
    });
    throw error;
  }
}

/**
 * Duplicates a product without images and with a new SKU.
 * @param id - The ID of the product to duplicate.
 * @param sku - The new SKU for the duplicated product.
 * @returns The duplicated product, or null if not found.
 */
async function duplicateProduct(
  id: string,
  sku: string,
): Promise<ProductWithImages | null> {
  await ErrorSystem.logInfo(`Duplicating product ${id} with new SKU ${sku}...`);
  try {
    const trimmedSku = sku.trim();
    const skuPattern = /^[A-Z0-9]+$/;
    if (!trimmedSku) {
      throw badRequestError("SKU is required", { field: "sku" });
    }
    if (!skuPattern.test(trimmedSku)) {
      throw badRequestError("SKU must use uppercase letters and numbers only", {
        field: "sku",
        value: trimmedSku,
      });
    }

    const productRepository = await resolveProductRepository();
    const duplicatedProduct = await productRepository.duplicateProduct(
      id,
      trimmedSku,
    );
    if (!duplicatedProduct) return null;
    return await getProductById(duplicatedProduct.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "duplicateProduct",
      productId: id,
      newSku: sku,
    });
    throw error;
  }
}

/**
 * Unlinks an image from a product.
 * @param productId - The ID of the product.
 * @param imageFileId - The ID of the image file.
 * @returns The result of the deletion.
 */
// Why: Images may be linked to multiple products. Only delete the physical file
// and folder after confirming no other products reference this image. This prevents
// accidental data loss if the same image is reused and orphaned disk directories
// from cluttering the storage.
async function unlinkImageFromProduct(
  productId: string,
  imageFileId: string,
): Promise<null> {
  const productRepository = await resolveProductRepository();
  const imageFileRepository = await resolveImageFileRepository();
  await productRepository.removeProductImage(productId, imageFileId);
  const remainingLinks =
    await productRepository.countProductsByImageFileId(imageFileId);

  if (remainingLinks === 0) {
    const imageFile = await imageFileRepository.getImageFileById(imageFileId);

    if (imageFile) {
      const isExternal = /^https?:\/\//i.test(imageFile.filepath);
      if (!isExternal) {
        try {
          await fs.unlink(getDiskPathFromPublicPath(imageFile.filepath));
        } catch (error: unknown) {
          if (
            error instanceof Error &&
            (error as NodeJS.ErrnoException).code !== "ENOENT"
          ) {
            throw error;
          }
        }
      }

      await imageFileRepository.deleteImageFile(imageFileId);

      if (!isExternal) {
        const folderDiskPath = path.dirname(
          getDiskPathFromPublicPath(imageFile.filepath),
        );
        if (
          folderDiskPath.startsWith(
            path.join(process.cwd(), "public", "uploads", "products"),
          )
        ) {
          try {
            const folderContents = await fs.readdir(folderDiskPath);
            if (folderContents.length === 0) {
              await fs.rmdir(folderDiskPath);
            }
          } catch (error: unknown) {
            if (
              error instanceof Error &&
              (error as NodeJS.ErrnoException).code !== "ENOENT"
            ) {
              throw error;
            }
          }
        }
      }
    }
  }

  return null;
}

/**
 * Links images to a product. This includes uploading new images and linking existing ones.
 * @param productId - The ID of the product.
 * @param images - The new image files to upload.
 * @param imageFileIds - The IDs of the existing image files to link.
 */
async function linkImagesToProduct(
  productId: string,
  images: File[],
  imageFileIds: string[],
  productSku?: string | null,
): Promise<void> {
  const productRepository = await resolveProductRepository();
  const allImageFileIds = [...imageFileIds];

  if (images.length > 0) {
    for (const image of images) {
      // Filter out empty file inputs
      if (image.size > 0) {
        const uploadedImage = await uploadFile(image, {
          category: "products",
          sku: productSku,
        });
        allImageFileIds.push(uploadedImage.id);
      }
    }
  }

  if (productSku && imageFileIds.length > 0) {
    await moveTempImageFilesToSku(imageFileIds, productSku);
  }

  if (allImageFileIds.length > 0) {
    await productRepository.addProductImages(productId, allImageFileIds);
  }
}

const tempProductPathPrefix = "/uploads/products/temp/";

// Why: HTML form's getAll("catalogIds") returns entries for EACH selected item.
// Normalize to trim whitespace (user selection artifacts) and filter empty strings
// (unchecked checkboxes). This prevents invalid IDs from entering the database.
function normalizeCatalogIds(entries: FormDataEntryValue[]): string[] {
  return entries
    .map((entry: FormDataEntryValue): string =>
      typeof entry === "string" ? entry.trim() : "",
    )
    .filter((entry: string): boolean => entry.length > 0);
}

function normalizeCategoryIds(entries: FormDataEntryValue[]): string[] {
  return entries
    .map((entry: FormDataEntryValue): string =>
      typeof entry === "string" ? entry.trim() : "",
    )
    .filter((entry: string): boolean => entry.length > 0);
}

function normalizeTagIds(entries: FormDataEntryValue[]): string[] {
  return entries
    .map((entry: FormDataEntryValue): string =>
      typeof entry === "string" ? entry.trim() : "",
    )
    .filter((entry: string): boolean => entry.length > 0);
}

async function updateProductCatalogs(
  productId: string,
  catalogIds: string[],
): Promise<void> {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductCatalogs(productId, catalogIds);

  // Why: Products need a default price group for inventory/listing calculations.
  // Auto-assigning from the first assigned catalog prevents incomplete product state.
  // Only sets it if the product doesn't already have one to preserve manual overrides.
  const firstCatalogId = catalogIds[0];
  if (firstCatalogId) {
    const product = await productRepository.getProductById(productId);
    if (product && !product.defaultPriceGroupId) {
      const catalogRepository = await getCatalogRepository();
      const catalog = await catalogRepository.getCatalogById(firstCatalogId);
      if (catalog?.defaultPriceGroupId) {
        await productRepository.updateProduct(productId, {
          defaultPriceGroupId: catalog.defaultPriceGroupId,
        });
      }
    }
  }
}

async function updateProductCategories(
  productId: string,
  categoryIds: string[],
): Promise<void> {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductCategories(productId, categoryIds);
}

async function updateProductTags(
  productId: string,
  tagIds: string[],
): Promise<void> {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductTags(productId, tagIds);
}

// Why: Temp path allows users to upload images before saving a product. Once a
// SKU is assigned, we permanently organize images by SKU for easy product recovery.
// Sanitization (replacing non-alphanumeric with underscore) prevents path injection
// and filesystem-specific naming issues across different OS environments.
async function moveTempImageFilesToSku(
  imageFileIds: string[],
  sku: string,
): Promise<void> {
  const imageFileRepository = await resolveImageFileRepository();
  const imageFiles =
    await imageFileRepository.findImageFilesByIds(imageFileIds);

  for (const imageFile of imageFiles) {
    if (!imageFile.filepath.startsWith(tempProductPathPrefix)) {
      continue;
    }

    const filename = imageFile.filepath.slice(tempProductPathPrefix.length);
    const safeSku = sku.trim().replace(/[^a-zA-Z0-9-_]/g, "_");
    const targetPublicDir = `/uploads/products/${safeSku}`;
    const targetPublicPath = `${targetPublicDir}/${filename}`;

    await fs.mkdir(
      path.join(process.cwd(), "public", "uploads", "products", safeSku),
      { recursive: true },
    );
    await fs.rename(
      getDiskPathFromPublicPath(imageFile.filepath),
      getDiskPathFromPublicPath(targetPublicPath),
    );

    await imageFileRepository.updateImageFilePath(
      imageFile.id,
      targetPublicPath,
    );
  }
}

async function moveLinkedTempImagesToSku(
  productId: string,
  sku: string,
): Promise<void> {
  const productRepository = await resolveProductRepository();
  const product = await productRepository.getProductById(productId);
  const imageFileIds =
    product?.images
      .filter((image: ProductImageRecord): boolean =>
        image.imageFile.filepath.startsWith(tempProductPathPrefix),
      )
      .map((image: ProductImageRecord): string => image.imageFileId) ?? [];
  if (imageFileIds.length > 0) {
    await moveTempImageFilesToSku(imageFileIds, sku);
  }
}

