"use client";

import { useQuery, useMutation, useQueryClient, type UseQueryResult, type UseMutationResult } from "@tanstack/react-query";
import { fetchAssets3D, fetchCategories, fetchTags } from "@/features/viewer3d/api";
import type { Asset3DListFilters, Asset3DRecord } from "@/features/viewer3d/types";

export const asset3dKeys = {
  all: ["assets3d"] as const,
  list: (filters: Asset3DListFilters) => ["assets3d", "list", filters] as const,
  categories: ["assets3d", "categories"] as const,
  tags: ["assets3d", "tags"] as const,
  detail: (id: string | null) => ["assets3d", "detail", id] as const,
};

export function useAssets3D(filters: Asset3DListFilters): UseQueryResult<Asset3DRecord[], Error> {
  return useQuery({
    queryKey: asset3dKeys.list(filters),
    queryFn: () => fetchAssets3D(filters),
  });
}

export function useAsset3DCategories(): UseQueryResult<string[], Error> {
  return useQuery({
    queryKey: asset3dKeys.categories,
    queryFn: fetchCategories,
  });
}

export function useAsset3DTags(): UseQueryResult<string[], Error> {
  return useQuery({
    queryKey: asset3dKeys.tags,
    queryFn: fetchTags,
  });
}

export function useAsset3DById(id: string | null): UseQueryResult<Asset3DRecord, Error> {
  return useQuery<Asset3DRecord>({
    queryKey: asset3dKeys.detail(id),
    queryFn: async () => {
      const res = await fetch(`/api/assets3d/${id}`);
      if (!res.ok) {
        throw new Error("Failed to fetch 3D asset");
      }
      return (await res.json()) as Asset3DRecord;
    },
    enabled: Boolean(id),
  });
}

export function useDeleteAsset3DMutation(): UseMutationResult<void, Error, string> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (id: string) => {
      const res = await fetch(`/api/assets3d/${id}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete 3D asset");
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: asset3dKeys.all });
    },
  });
}

export function useUpdateAsset3DMutation(): UseMutationResult<Asset3DRecord, Error, { id: string; data: Partial<Asset3DRecord> }> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ id, data }) => {
      const res = await fetch(`/api/assets3d/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!res.ok) throw new Error("Failed to update 3D asset");
      return res.json();
    },
    onSuccess: (data) => {
      void queryClient.invalidateQueries({ queryKey: asset3dKeys.all });
      void queryClient.invalidateQueries({ queryKey: asset3dKeys.detail(data.id) });
    },
  });
}

import { useEffect, useState } from "react";

export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return (): void => {
      clearTimeout(timer);
    };
  }, [value, delay]);

  return debouncedValue;
}

import { useState, useCallback, useRef } from "react";

interface UseUndoResult<T> {
  state: T;
  setState: (newState: T, skipHistory?: boolean) => void;
  undo: () => void;
  redo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  resetHistory: (initialState: T) => void;
}

export function useUndo<T>(
  initialState: T,
  limit: number = 50,
): UseUndoResult<T> {
  const [state, setInnerState] = useState<T>(initialState);
  const [history, setHistory] = useState<T[]>([initialState]);
  const [index, setIndex] = useState(0);
  const limitRef = useRef(limit);

  // We use a ref to track if we should merge rapid updates (optional, usually good for typing)
  // For now, straightforward implementation.

  const setState = useCallback(
    (newState: T, skipHistory: boolean = false): void => {
      setInnerState(newState);

      if (skipHistory) return;

      setHistory((prev: T[]) => {
        const currentHistory = prev.slice(0, index + 1);
        const nextHistory = [...currentHistory, newState];
        if (nextHistory.length > limitRef.current) {
          nextHistory.shift();
          return nextHistory;
        }
        return nextHistory;
      });
      setIndex((prev: number) => {
        const next = prev + 1;
        return next >= limitRef.current ? limitRef.current - 1 : next;
      });
    },
    [index],
  );

  const undo = useCallback((): void => {
    if (index > 0) {
      setIndex((prev: number) => prev - 1);
      setInnerState(history[index - 1]!);
    }
  }, [history, index]);

  const redo = useCallback((): void => {
    if (index < history.length - 1) {
      setIndex((prev: number) => prev + 1);
      setInnerState(history[index + 1]!);
    }
  }, [history, index]);

  const resetHistory = useCallback((newState: T): void => {
    setInnerState(newState);
    setHistory([newState]);
    setIndex(0);
  }, []);

  return {
    state,
    setState,
    undo,
    redo,
    canUndo: index > 0,
    canRedo: index < history.length - 1,
    resetHistory,
  };
}

import "server-only";

import { NextRequest, NextResponse } from "next/server";
import { randomUUID } from "crypto";
import { resolveError } from "@/shared/errors/resolve-error";
import { getErrorFingerprint, logSystemEvent } from "@/features/observability/server";
import { badRequestError } from "@/shared/errors/app-error";
import type { SystemLogLevel } from "@/shared/types/system-logs";
import type {
  ApiHandlerOptions,
  ApiHandlerContext,
  ApiRouteHandler,
  ApiRouteHandlerWithParams,
} from "@/shared/types/api";

export type {
  ApiHandlerOptions,
  ApiHandlerContext,
  ApiRouteHandler,
  ApiRouteHandlerWithParams,
};

/**
 * Wraps an API route handler with automatic error handling, logging, and request tracking.
 *
 * Features:
 * - Automatic error catching and standardized error responses
 * - Request ID generation and tracking
 * - Performance timing
 * - Structured logging for both errors and successes
 * - Consistent error response format
 *
 * @example
 * ```ts
 * export const GET = apiHandler(
 *   async (req, ctx) => {
 *     const data = await fetchData();
 *     return NextResponse.json(data);
 *   },
 *   { source: "products.GET" }
 * );
 * ```
 */
export function apiHandler(
  handler: ApiRouteHandler,
  options: ApiHandlerOptions
): (request: NextRequest) => Promise<Response> {
  return async (request: NextRequest) => {
    const requestId = request.headers.get("x-request-id") ?? randomUUID();
    const startTime = performance.now();

    const context: ApiHandlerContext = {
      requestId,
      startTime,
      getElapsedMs: (): number => Math.round(performance.now() - startTime),
    };

    try {
      const response = await handler(request, context);

      // Log successful requests if configured
      if (options.logSuccess) {
        void logSystemEvent({
          level: options.successLogLevel ?? "info",
          message: `${options.source} completed successfully`,
          source: options.source,
          request,
          requestId,
          statusCode: response.status,
          context: {
            durationMs: context.getElapsedMs(),
          },
        });
      }

      // Add request ID to response headers for client-side tracking
      if (!response.headers.has("x-request-id")) {
        response.headers.set("x-request-id", requestId);
      }
      return response;
    } catch (error) {
      return createErrorResponseWithTiming(error, request, context, options);
    }
  };
}

/**
 * Wraps an API route handler with params (for dynamic routes like [id]).
 *
 * @example
 * ```ts
 * export const GET = apiHandlerWithParams<{ id: string }>(
 *   async (req, ctx, params) => {
 *     const item = await getById(params.id);
 *     return NextResponse.json(item);
 *   },
 *   { source: "products/[id].GET" }
 * );
 * ```
 */
export function apiHandlerWithParams<P extends Record<string, string>>(
  handler: ApiRouteHandlerWithParams<P>,
  options: ApiHandlerOptions
): (
  request: NextRequest,
  context: { params: Promise<P> }
) => Promise<Response> {
  return async (request: NextRequest, routeContext: { params: Promise<P> }) => {
    const requestId = request.headers.get("x-request-id") ?? randomUUID();
    const startTime = performance.now();

    const handlerContext: ApiHandlerContext = {
      requestId,
      startTime,
      getElapsedMs: () => Math.round(performance.now() - startTime),
    };

    try {
      const params = await routeContext.params;
      const response = await handler(request, handlerContext, params);

      if (options.logSuccess) {
        void logSystemEvent({
          level: options.successLogLevel ?? "info",
          message: `${options.source} completed successfully`,
          source: options.source,
          request,
          requestId,
          statusCode: response.status,
          context: {
            durationMs: handlerContext.getElapsedMs(),
            params,
          },
        });
      }

      if (!response.headers.has("x-request-id")) {
        response.headers.set("x-request-id", requestId);
      }
      return response;
    } catch (error) {
      return createErrorResponseWithTiming(
        error,
        request,
        handlerContext,
        options
      );
    }
  };
}

/**
 * Creates an error response with timing information and logging.
 */
function createErrorResponseWithTiming(
  error: unknown,
  request: NextRequest,
  context: ApiHandlerContext,
  options: ApiHandlerOptions
): Response {
  const resolved = resolveError(error, {
    ...(options.fallbackMessage !== undefined && { fallbackMessage: options.fallbackMessage }),
  });

  const level: SystemLogLevel = resolved.expected ? "warn" : "error";
  const durationMs = context.getElapsedMs();

  // Log the error with full context
  void logSystemEvent({
    level,
    message: resolved.message,
    source: options.source,
    error,
    request,
    requestId: context.requestId,
    statusCode: resolved.httpStatus,
    context: {
      errorId: resolved.errorId,
      code: resolved.code,
      durationMs,
      ...(resolved.meta ? { meta: resolved.meta } : {}),
    },
  });

  // Build response payload
  const payload: Record<string, unknown> = {
    error: resolved.message,
    code: resolved.code,
    errorId: resolved.errorId,
  };

  const fingerprint = getErrorFingerprint({
    message: resolved.message,
    source: options.source,
    request,
    statusCode: resolved.httpStatus,
    error,
  });

  payload.fingerprint = fingerprint;

  if (resolved.retryable) {
    payload.retryable = true;
    if (resolved.retryAfterMs) {
      payload.retryAfterMs = resolved.retryAfterMs;
    }
  }

  if (resolved.expected && resolved.meta) {
    payload.details = resolved.meta;
  } else if (options.includeDetails && resolved.meta) {
    payload.details = resolved.meta;
  }

  const response = NextResponse.json(payload, { status: resolved.httpStatus });
  response.headers.set("x-request-id", context.requestId);
  response.headers.set("x-error-id", resolved.errorId);
  response.headers.set("x-error-fingerprint", fingerprint);

  if (resolved.retryable && resolved.retryAfterMs) {
    const retryAfterSeconds = Math.ceil(resolved.retryAfterMs / 1000);
    response.headers.set("Retry-After", String(retryAfterSeconds));
  }

  return response;
}

/**
 * Helper to extract common query parameters.
 */
export function getQueryParams(request: NextRequest): URLSearchParams {
  return new URL(request.url).searchParams;
}

/**
 * Helper to get a required query parameter, throws if missing.
 */
export function getRequiredParam(
  searchParams: URLSearchParams,
  name: string
): string {
  const value = searchParams.get(name);
  if (!value) {
    throw badRequestError(`Missing required parameter: ${name}`);
  }
  return value;
}

/**
 * Helper to parse pagination parameters.
 */
export function getPaginationParams(searchParams: URLSearchParams): {
  page: number;
  pageSize: number;
  skip: number;
} {
  const page = Math.max(1, parseInt(searchParams.get("page") ?? "1", 10));
  const pageSize = Math.min(
    100,
    Math.max(1, parseInt(searchParams.get("pageSize") ?? "20", 10))
  );
  const skip = (page - 1) * pageSize;
  return { page, pageSize, skip };
}

import "server-only";

import { NextResponse } from "next/server";
import { randomUUID } from "crypto";
import { resolveError } from "@/shared/errors/resolve-error";
import { getErrorFingerprint, logSystemEvent } from "@/features/observability/server";
import { validationError } from "@/shared/errors/app-error";

type ApiErrorOptions = {
  request?: Request | undefined;
  source?: string | undefined;
  fallbackMessage?: string | undefined;
  includeDetails?: boolean | undefined;
  extra?: Record<string, unknown> | undefined;
  /** Request ID for tracing (will be included in response headers) */
  requestId?: string | undefined;
};

/**
 * Creates a standardized error response with logging.
 *
 * Features:
 * - Resolves any error to a standardized format
 * - Logs to system log with appropriate level
 * - Includes retry information for retryable errors
 * - Sets appropriate headers (x-request-id, x-error-id, Retry-After)
 * - Differentiates between expected (user) and unexpected (server) errors
 */
export const createErrorResponse = (
  error: unknown,
  options?: ApiErrorOptions
): NextResponse => {
  const resolved = resolveError(error, {
    ...(options?.fallbackMessage ? { fallbackMessage: options.fallbackMessage } : {}),
  });

  const requestId =
    options?.requestId ??
    options?.request?.headers.get("x-request-id") ??
    randomUUID();

  const fingerprint = getErrorFingerprint({
    message: resolved.message,
    source: options?.source ?? "api",
    ...(options?.request ? { request: options.request } : {}),
    statusCode: resolved.httpStatus,
    error,
  });

  // Determine log level based on error type
  const level = resolved.critical ? "error" : resolved.expected ? "warn" : "error";

  // Log the error
  void logSystemEvent({
    level,
    message: resolved.message,
    source: options?.source ?? "api",
    error,
    ...(options?.request ? { request: options.request } : {}),
    requestId,
    statusCode: resolved.httpStatus,
    context: {
      errorId: resolved.errorId,
      code: resolved.code,
      critical: resolved.critical,
      retryable: resolved.retryable,
      ...(resolved.retryAfterMs ? { retryAfterMs: resolved.retryAfterMs } : {}),
      ...(resolved.meta ? { meta: resolved.meta } : {}),
    },
  });

  // Build response payload
  const payload: Record<string, unknown> = {
    error: resolved.message,
    code: resolved.code,
    errorId: resolved.errorId,
    fingerprint,
  };

  // Include retry information for retryable errors
  if (resolved.retryable) {
    payload.retryable = true;
    if (resolved.retryAfterMs) {
      payload.retryAfterMs = resolved.retryAfterMs;
    }
  }

  // Include details for expected errors or when explicitly requested
  if (resolved.expected && resolved.meta) {
    payload.details = resolved.meta;
  } else if (options?.includeDetails && resolved.meta) {
    payload.details = resolved.meta;
  }

  // Merge any extra payload fields
  if (options?.extra) {
    Object.assign(payload, options.extra);
  }

  // Create response
  const response = NextResponse.json(payload, { status: resolved.httpStatus });

  // Set tracking headers
  response.headers.set("x-request-id", requestId);
  response.headers.set("x-error-id", resolved.errorId);
  response.headers.set("x-error-fingerprint", fingerprint);

  // Set Retry-After header for retryable errors
  if (resolved.retryable && resolved.retryAfterMs) {
    // Convert to seconds for HTTP header
    const retryAfterSeconds = Math.ceil(resolved.retryAfterMs / 1000);
    response.headers.set("Retry-After", String(retryAfterSeconds));
  }

  return response;
};

/**
 * Creates a simple error response without logging.
 * Use sparingly - prefer createErrorResponse for proper tracing.
 */
export const createSimpleErrorResponse = (
  message: string,
  status: number,
  code?: string
): NextResponse => {
  return NextResponse.json(
    {
      error: message,
      code: code ?? "ERROR",
    },
    { status }
  );
};

/**
 * Creates a validation error response from field errors.
 */
export const createValidationErrorResponse = (
  fieldErrors: Record<string, string[]>,
  options?: Pick<ApiErrorOptions, "request" | "source" | "requestId">
): NextResponse => {
  const error = validationError("Validation failed", { fields: fieldErrors });
  return createErrorResponse(error, options);
};

